using UnityEngine;
using UnityEngine.SceneManagement;
using Sttop5.Shared.Core;

namespace TowerDefense.Module
{
    /// <summary>
    /// 塔防场景桥接器，处理从家园进入塔防和从塔防返回家园的场景切换。
    /// 挂载在 TDGameScene 中。
    /// </summary>
    public class TDSceneBridge : MonoBehaviour
    {
        [Header("返回家园配置")]
        [SerializeField] private string _homeSceneName = "HomeScene";

        /// <summary>
        /// 从塔防返回家园。由 UI 按钮调用。
        /// </summary>
        public void ReturnToHome()
        {
            Debug.Log("[TDSceneBridge] 返回家园...");

            // 保存塔防数据
            SaveCurrentState();

            // 停用模块（会清理状态并卸载场景）
            ModuleManager.Instance.DeactivateCurrentModule();
        }

        /// <summary>
        /// 重新开始当前塔防关卡。
        /// </summary>
        public void RestartCurrentLevel()
        {
            Debug.Log("[TDSceneBridge] 重新开始关卡");

            var gameManager = Core.GameManager.Instance;
            if (gameManager != null)
            {
                Time.timeScale = 1f;
                gameManager.RestartGame();
            }
        }

        /// <summary>
        /// 进入塔防模块（从家园调用）。
        /// </summary>
        public static void EnterTowerDefense()
        {
            Debug.Log("[TDSceneBridge] 进入塔防模块");
            ModuleManager.Instance.ActivateModule("towerdefense");
        }

        private void SaveCurrentState()
        {
            var module = TowerDefenseGameModule.Instance;
            if (module != null)
            {
                string saveData = module.GetModuleSaveData();
                Sttop5.Shared.Save.SaveSystem.Instance?.SaveModuleData("towerdefense", saveData, 1);
            }
        }
    }
}

using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace TowerDefense.Module
{
    /// <summary>
    /// 塔防游戏模块，继承共享 GameModule 基类。
    /// 作为塔防玩法在 HomeBase 架构中的入口。
    /// </summary>
    public class TowerDefenseGameModule : GameModule
    {
        [Header("模块配置")]
        [SerializeField] private string _moduleIdInternal = "towerdefense";
        [SerializeField] private string _displayNameInternal = "塔防";
        [SerializeField] private string _sceneNameInternal = "TDGameScene";

        /// <summary>当前模块实例</summary>
        public static TowerDefenseGameModule Instance { get; private set; }

        private void Reset()
        {
            _moduleId = _moduleIdInternal;
            _displayName = _displayNameInternal;
            _sceneName = _sceneNameInternal;
        }

        private void Awake()
        {
            if (string.IsNullOrEmpty(_moduleId)) _moduleId = _moduleIdInternal;
            if (string.IsNullOrEmpty(_displayName)) _displayName = _displayNameInternal;
            if (string.IsNullOrEmpty(_sceneName)) _sceneName = _sceneNameInternal;

            Instance = this;
        }

        public override void Activate()
        {
            // 设置全局模块模式标志
            Core.ModuleModeDetector.IsModuleMode = true;

            base.Activate();

            // 注册到模块管理器
            ModuleManager.Instance.RegisterModule(this);

            Debug.Log("[TowerDefenseGameModule] 塔防模块已激活（模块模式）");
        }

        public override void Deactivate()
        {
            CleanupTowerDefenseState();

            // 清除全局模块模式标志
            Core.ModuleModeDetector.IsModuleMode = false;

            Instance = null;
            base.Deactivate();

            Debug.Log("[TowerDefenseGameModule] 塔防模块已停用");
        }

        /// <summary>
        /// 清理塔防运行状态，确保回到家园时无残留。
        /// </summary>
        private void CleanupTowerDefenseState()
        {
            // 重置时间缩放
            Time.timeScale = 1f;

            // 清理塔防 EventBus
            Core.EventBus.Clear();

            // 停止所有协程
            StopAllCoroutines();
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var adapter = new TDSaveAdapter();
            return adapter.CollectSaveData();
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            var adapter = new TDSaveAdapter();
            adapter.RestoreSaveData(jsonData);
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Core;

namespace TowerDefense.Enemy
{
    [RequireComponent(typeof(EnemyMovement), typeof(EnemyHealth))]
    public class Enemy : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private EnemyData _enemyData;

        [Header("Health Bar")]
        [SerializeField] private Slider _healthSlider;
        [SerializeField] private Image _healthFillImage;
        [SerializeField] private Color _lowHealthColor = Color.red;
        [SerializeField] private Color _mediumHealthColor = Color.yellow;
        [SerializeField] private Color _highHealthColor = Color.green;
        [SerializeField] private float _healthBarOffsetY = 1.5f;

        private EnemyMovement _movement;
        private EnemyHealth _health;
        private Canvas _healthCanvas;

        public EnemyData Data => _enemyData;
        public EnemyMovement Movement => _movement;
        public EnemyHealth Health => _health;
        public bool IsDead => _health != null && _health.CurrentHealth <= 0;

        private int _birthWaveId = -1;  // 敌人归属的波次ID

        // 给 EnemySpawner 调用的
        public void SetBirthWaveId(int waveId)
        {
            _birthWaveId = waveId;
        }

        private void Awake()
        {
            _movement = GetComponent<EnemyMovement>();
            _health = GetComponent<EnemyHealth>();

            // 获取血条画布
            if (_healthSlider != null)
            {
                _healthCanvas = _healthSlider.GetComponentInParent<Canvas>();
                _healthSlider.value = 1f;
            }

            if (_enemyData != null)
            {
                Initialize(_enemyData);
            }
        }

        public void Initialize(EnemyData data)
        {
            _enemyData = data;

            if (_health != null)
            {
                _health.Initialize(data.stats.maxHealth, data.stats.goldReward);
                _health.OnHealthChanged += UpdateHealthBar;
                _health.OnDeath += OnDeath;
            }

            if (_movement != null)
            {
                _movement.SetSpeed(data.stats.moveSpeed);
            }

            // 初始化血条
            UpdateHealthBar(data.stats.maxHealth, data.stats.maxHealth);
        }

        public void StartMovement(PathCreator pathCreator)
        {
            if (_movement != null)
            {
                _movement.FollowPath(pathCreator);
            }
        }

        public void OnReachedEnd()
        {
            // 敌人走到终点也统计为波次敌人不再场
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            if (GameManager.Instance != null)
            {
                GameManager.Instance.TakeDamage(_enemyData.stats.lifeDamage);
            }
            EventBus.Publish(new EnemyReachEndEvent { Enemy = gameObject, Damage = _enemyData.stats.lifeDamage });
            Destroy(gameObject);
        }

        public void OnDeath()
        {
            // 波次统计-带上GameObject给HashSet去重
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            // 解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }

            // 隐藏血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = false;
            }

            if (GameManager.Instance != null)
            {
                GameManager.Instance.AddGold(_enemyData.stats.goldReward);
                GameManager.Instance.AddKill();
            }
            EventBus.Publish(new EnemyDeathEvent { Enemy = gameObject, Reward = _enemyData.stats.goldReward });
            Destroy(gameObject);
        }

        private void Update()
        {
            // 更新血条位置，始终在敌人头顶
            UpdateHealthBarPosition();
        }

        private void UpdateHealthBar(int currentHealth, int maxHealth)
        {
            if (_healthSlider == null) return;

            float healthPercent = (float)currentHealth / maxHealth;
            _healthSlider.value = healthPercent;

            // 根据血量改变颜色
            UpdateHealthBarColor(healthPercent);

            // 当血量低于最大值时显示血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = healthPercent < 1f;
            }
        }

        private void UpdateHealthBarColor(float healthPercent)
        {
            if (_healthFillImage == null) return;

            if (healthPercent <= 0.3f)
            {
                _healthFillImage.color = _lowHealthColor;
            }
            else if (healthPercent <= 0.6f)
            {
                _healthFillImage.color = _mediumHealthColor;
            }
            else
            {
                _healthFillImage.color = _highHealthColor;
            }
        }

        private void UpdateHealthBarPosition()
        {
            if (_healthSlider == null || _healthCanvas == null) return;

            // 将世界坐标转换为屏幕坐标
            Vector3 worldPosition = transform.position;
            worldPosition.y += _healthBarOffsetY;

            // 如果是世界空间画布，直接设置位置
            if (_healthCanvas.renderMode == RenderMode.WorldSpace)
            {
                _healthSlider.transform.position = worldPosition;
            }
            else
            {
                // 如果是屏幕空间画布，转换坐标
                Vector3 screenPosition = Camera.main.WorldToScreenPoint(worldPosition);
                _healthSlider.transform.position = screenPosition;
            }
        }

        private void OnDestroy()
        {
            // 确保解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }
        }

        public void TakeDamage(int damage)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage);
            }
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage, damageType);
            }
        }

        public void ApplySlow(float slowFactor, float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(slowFactor, duration);
            }
        }

        public void ApplyStun(float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(0f, duration);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Core;

namespace TowerDefense.Wave
{
    public class WaveManager : MonoBehaviour
    {
        public static WaveManager Instance { get; private set; }

        [Header("Settings")]
        [SerializeField] private EnemySpawner _enemySpawner;
        [SerializeField] private float _waveDelay = 5f;
        [SerializeField] private int _totalWaves = 5;
        [SerializeField] private int _baseEnemyCount = 5;
        [SerializeField] private int _enemyIncreasePerWave = 2;

        [Header("Wave Data (Optional)")]
        [Tooltip("如果设置了这个数组，将使用这里的配置而不是动态生成")]
        [SerializeField] private WaveData[] _waveDatas;

        [Header("Enemy Data")]
        [Tooltip("所有可用的敌人数据（飞机、骷髅等）")]
        [SerializeField] private EnemyData[] _enemyDatas;

        private EnemyData _defaultEnemyData;

        [Header("UI")]
        [SerializeField] private Text _waveText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Text _waveAnnounceText;
        [SerializeField] private float _announceDuration = 2f;

        private int _currentWaveIndex = 0;
        private float _waveTimer = 0f;
        private bool _isWaveActive = false;
        private bool _isWaveTransition = false;

        public int CurrentWave => _currentWaveIndex;
        public int TotalWaves => _totalWaves;
        public bool IsWaveActive => _isWaveActive;

        private void Awake()
        {
            if (Instance == null)
            {
                Instance = this;
            }
            else
            {
                Destroy(gameObject);
            }
        }

        private void Start()
        {
            LoadEnemyData();
            UpdateWaveUI();

            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }

            EventBus.Subscribe<GameStartEvent>(OnGameStart);
        }

        private void LoadEnemyData()
        {
            // 如果在 Inspector 中设置了敌人数据数组，直接使用
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                Debug.Log($"已加载 {_enemyDatas.Length} 个敌人数据");
                foreach (var enemy in _enemyDatas)
                {
                    Debug.Log($"  - {enemy.enemyName}");
                }
                // 使用第一个作为默认
                _defaultEnemyData = _enemyDatas[0];
                return;
            }

            // 否则尝试从 Resources 加载
            _defaultEnemyData = Resources.Load<EnemyData>("Data/EnemyData");
            if (_defaultEnemyData == null)
            {
                Debug.LogError("Failed to load EnemyData from Resources/Data/EnemyData");
            }
        }

        private void OnDestroy()
        {
            EventBus.Unsubscribe<GameStartEvent>(OnGameStart);
        }

        private void OnGameStart(GameStartEvent e)
        {
            ForceStartWave();
        }

        private void Update()
        {
            if (_isWaveTransition && !_isWaveActive)
            {
                _waveTimer += Time.deltaTime;

                float remainingTime = _waveDelay - _waveTimer;

                if (remainingTime > 0)
                {
                    UpdateWaveCountdown((int)Mathf.CeilToInt(remainingTime));
                }

                if (remainingTime % 1f < 0.05f)
                {
                    Debug.Log($"倒计时更新: timer={_waveTimer:F1}/{_waveDelay}, 剩余={remainingTime:F1}s, transition={_isWaveTransition}, active={_isWaveActive}");
                }

                if (_waveTimer >= _waveDelay)
                {
                    Debug.Log($"✅ 倒计时结束, 准备开始下一波!");
                    _waveTimer = 0f;
                    HideWaveCountdown();
                    StartNextWave();
                }
            }

            UpdateEnemyCountDisplay();
        }

        private void UpdateWaveCountdown(int seconds)
        {
            if (_waveAnnounceText != null)
            {
                int nextWave = _currentWaveIndex + 1;
                _waveAnnounceText.text = $"第 {nextWave} 波 {seconds} 秒后出现！";
                _waveAnnounceText.gameObject.SetActive(true);
            }
        }

        private void HideWaveCountdown()
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private void UpdateEnemyCountDisplay()
        {
            if (_enemyCountText != null)
            {
                // 用 EnemySpawner 追踪的波次剩余敌人（出生总数 - 死亡数）
                _enemyCountText.text = $"剩余敌人:{TowerDefense.Enemy.EnemySpawner.RemainingEnemies}";
            }
        }

        public void StartNextWave()
        {
            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log("All waves completed!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
                return;
            }

            // 先增加波次索引
            _currentWaveIndex++;

            WaveData waveData = GetWaveData();
            if (waveData == null)
            {
                Debug.LogError("Failed to get wave data!");
                return;
            }

            _enemySpawner.StartWave(waveData);

            _isWaveActive = true;
            _isWaveTransition = false;

            if (GameManager.Instance != null)
            {
                GameManager.Instance.SetCurrentWave(_currentWaveIndex);
            }

            EventBus.Publish(new WaveStartEvent { WaveIndex = _currentWaveIndex });

            UpdateWaveUI();
            StartCoroutine(ShowWaveAnnouncement(_currentWaveIndex));
            Debug.Log($"Starting wave {_currentWaveIndex}");
        }

        private IEnumerator ShowWaveAnnouncement(int waveNumber)
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.text = $"第 {waveNumber} 波开始出怪！";
                _waveAnnounceText.gameObject.SetActive(true);

                Debug.Log($"📢 {_waveAnnounceText.text}");

                yield return new WaitForSeconds(_announceDuration);

                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private WaveData GetWaveData()
        {
            // 如果用户设置了 WaveData 数组，使用它
            if (_waveDatas != null && _waveDatas.Length > 0)
            {
                int index = _currentWaveIndex - 1;
                if (index >= 0 && index < _waveDatas.Length)
                {
                    Debug.Log($"使用配置的 WaveData: 波次 {_currentWaveIndex}");
                    return _waveDatas[index];
                }
            }

            // 否则动态生成
            if (_defaultEnemyData == null && (_enemyDatas == null || _enemyDatas.Length == 0))
            {
                Debug.LogError("No EnemyData available! Cannot create wave data.");
                return null;
            }

            Debug.Log($"动态生成 WaveData: 波次 {_currentWaveIndex}");
            return CreateWaveData();
        }

        private WaveData CreateWaveData()
        {
            WaveData waveData = ScriptableObject.CreateInstance<WaveData>();
            waveData.waveNumber = _currentWaveIndex;
            waveData.spawnInterval = Mathf.Max(0.5f, 1.5f - (_currentWaveIndex - 1) * 0.1f);
            waveData.enemies = new List<WaveData.WaveEnemy>();

            int totalEnemies = _baseEnemyCount + (_currentWaveIndex - 1) * _enemyIncreasePerWave;

            // 使用多个敌人数据
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                // 随机选择敌人
                for (int i = 0; i < _enemyDatas.Length; i++)
                {
                    int enemyCount = totalEnemies / _enemyDatas.Length;
                    if (i == 0)
                    {
                        enemyCount += totalEnemies % _enemyDatas.Length;
                    }

                    if (enemyCount > 0)
                    {
                        waveData.enemies.Add(new WaveData.WaveEnemy
                        {
                            enemyData = _enemyDatas[i],
                            count = enemyCount,
                            spawnDelay = 0,
                            spawnPoint = "MainPath"
                        });

                        Debug.Log($"波次 {_currentWaveIndex} 添加 {enemyCount} 个 {_enemyDatas[i].enemyName}");
                    }
                }
            }
            else
            {
                // 只有一个敌人数据时使用旧方法
                waveData.enemies.Add(new WaveData.WaveEnemy
                {
                    enemyData = _defaultEnemyData,
                    count = totalEnemies,
                    spawnDelay = 0,
                    spawnPoint = "MainPath"
                });
            }

            return waveData;
        }

        public void OnWaveComplete()
        {
            _isWaveActive = false;

            Debug.Log($"波次 {_currentWaveIndex}/{_totalWaves} 完成!");
            EventBus.Publish(new WaveEndEvent { WaveIndex = _currentWaveIndex });

            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log($"全部波次完成!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
            }
            else
            {
                _isWaveTransition = true;
                _waveTimer = 0f;
            }

            UpdateWaveUI();
        }

        public void StartWaveManually(int waveIndex)
        {
            if (waveIndex >= 0 && waveIndex < _totalWaves)
            {
                _currentWaveIndex = waveIndex;
                StartNextWave();
            }
        }

        public void SkipToNextWave()
        {
            if (!_isWaveActive && _currentWaveIndex < _totalWaves)
            {
                StartNextWave();
            }
        }

        public void ForceStartWave()
        {
            if (!_isWaveActive)
            {
                _isWaveTransition = false;
                _waveTimer = 0f;
                StartNextWave();
            }
        }

        private void UpdateWaveUI()
        {
            if (_waveText != null)
            {
                _waveText.text = $"波次:{_currentWaveIndex}/{_totalWaves}";
            }

            UpdateEnemyCountDisplay();
        }

        public void Reset()
        {
            _currentWaveIndex = 0;
            _waveTimer = 0f;
            _isWaveActive = false;
            _isWaveTransition = false;
            UpdateWaveUI();
        }
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 500;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;

        private LevelData _currentLevelData;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        /// <summary>是否以模块模式运行</summary>
        private bool _isModuleMode;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;
        public bool IsModuleMode => _isModuleMode;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            // 检测模块模式：通过场景名或全局标志判断
            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下不使用 DontDestroyOnLoad
                // 单例实例存在但不跨场景持久化
                // 使用 base.Instance 静态属性检测重复实例
                var existingInstance = FindObjectOfType<GameManager>();
                if (existingInstance != null && existingInstance != this)
                {
                    Destroy(gameObject);
                    return;
                }
                // 不调用 base.Awake()，避免 DontDestroyOnLoad
            }
            else
            {
                base.Awake();
            }

            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene" || sceneName == "TDGameScene")
            {
                LoadLevel(0);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = 0 });
            OnLifeChanged?.Invoke(_currentLife);

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;

            // 持久化玩家等级数据
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });

            if (isVictory)
            {
                Data.PlayerLevelSystem.Instance?.AddExp(50 + _currentWave * 10);
            }
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            // 模块模式下发布 MiniGameCompletedEvent
            if (_isModuleMode)
            {
                Sttop5.Shared.Core.GlobalEventBus.Publish(new Sttop5.Shared.Core.MiniGameCompletedEvent
                {
                    ModuleId = "towerdefense",
                    IsVictory = isVictory,
                    StarsEarned = isVictory ? CalculateStars() : 0,
                    GoldReward = isVictory ? _currentWave * 20 : 0,
                    ExpReward = isVictory ? 50 + _currentWave * 10 : 0
                });
            }
        }

        private int CalculateStars()
        {
            float lifeRatio = (float)_currentLife / _initialLife;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;

            if (_isModuleMode)
            {
                // 模块模式下重载 TDGameScene
                var sceneLoader = Sttop5.Shared.Core.SceneLoader.Instance;
                if (sceneLoader != null)
                {
                    sceneLoader.UnloadScene("TDGameScene", () =>
                    {
                        sceneLoader.LoadSceneAdditive("TDGameScene");
                    });
                }
                else
                {
                    UnityEngine.SceneManagement.SceneManager.LoadScene(
                        UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                    );
                }
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene(
                    UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                );
            }
        }

        /// <summary>
        /// 返回家园（模块模式下使用）。
        /// </summary>
        public void ReturnToHome()
        {
            if (_isModuleMode)
            {
                Time.timeScale = 1f;
                Sttop5.Shared.Core.ModuleManager.Instance.DeactivateCurrentModule();
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene("MainMenu");
            }
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
            Data.PlayerLevelSystem.Instance?.AddExp(5);
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

