using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源管理器，管理家园中的资源产出和收集。
    /// </summary>
    public class ResourceManager : MonoBehaviour
    {
        [Header("本地资源")]
        [SerializeField] private int _wood = 0;
        [SerializeField] private int _stone = 0;
        [SerializeField] private int _food = 0;

        public int Wood => _wood;
        public int Stone => _stone;
        public int Food => _food;

        public event Action<int, int, int> OnLocalResourcesChanged;

        #region 本地资源操作

        public void AddWood(int amount)
        {
            if (amount <= 0) return;
            _wood += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddStone(int amount)
        {
            if (amount <= 0) return;
            _stone += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddFood(int amount)
        {
            if (amount <= 0) return;
            _food += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public bool SpendWood(int amount)
        {
            if (_wood < amount) return false;
            _wood -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendStone(int amount)
        {
            if (_stone < amount) return false;
            _stone -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendFood(int amount)
        {
            if (_food < amount) return false;
            _food -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        #endregion

        #region 收集所有建筑产出

        /// <summary>
        /// 收集所有资源建筑的产出。
        /// </summary>
        public void CollectAllResources()
        {
            var buildingManager = FindObjectOfType<BuildingManager>();
            if (buildingManager == null) return;

            int totalCollected = 0;
            foreach (var building in buildingManager.Buildings)
            {
                var resourceBuilding = building as ResourceBuilding;
                if (resourceBuilding != null)
                {
                    totalCollected += resourceBuilding.CollectResources();
                }
            }

            if (totalCollected > 0)
            {
                Debug.Log($"[ResourceManager] 收集所有建筑产出: {totalCollected}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave(HomeSaveData data)
        {
            if (data == null) return;
            _wood = data.wood;
            _stone = data.stone;
            _food = data.food;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void SaveToSave(HomeSaveData data)
        {
            data.wood = _wood;
            data.stone = _stone;
            data.food = _food;
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;
        [SerializeField] private Image _dimOverlay;  // 半透明遮罩

        [Header("Currency Display")]
        [SerializeField] private Text _goldAmountText;
        [SerializeField] private Text _diamondAmountText;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private GameObject _tabIndicator;  // 滑动指示器
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;
        [Header("Confirm Dialog")]
        [SerializeField] private GameObject _confirmDialog;
        [SerializeField] private Text _confirmTitleText;
        [SerializeField] private Text _confirmDescText;
        [SerializeField] private Text _confirmPriceText;
        [SerializeField] private Button _confirmBuyButton;
        [SerializeField] private Button _confirmCancelButton;

        [Header("Feedback")]
        [SerializeField] private GameObject _feedbackPanel;
        [SerializeField] private Text _feedbackText;
        [SerializeField] private float _feedbackDuration = 1.5f;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private ShopItemData _pendingBuyItem;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();
        private Dictionary<ShopCategory, Vector3> _tabPositions = new Dictionary<ShopCategory, Vector3>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;
        private Coroutine _feedbackCoroutine;

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                    // 记录每个Tab的位置用于指示器滑动
                    _tabPositions[cat] = kvp.Value.transform.localPosition;
                }
            }

            // 确认弹窗按钮
            if (_confirmBuyButton != null)
                _confirmBuyButton.onClick.AddListener(OnConfirmBuy);
            if (_confirmCancelButton != null)
                _confirmCancelButton.onClick.AddListener(OnCancelBuy);

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            if (_feedbackPanel != null)
                _feedbackPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            // 半透明遮罩
            if (_dimOverlay != null)
            {
                _dimOverlay.gameObject.SetActive(true);
                _dimOverlay.color = new Color(0, 0, 0, 0.6f);
            }

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadShopData();
            UpdateCurrencyDisplay();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);

            if (_dimOverlay != null)
                _dimOverlay.gameObject.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void UpdateCurrencyDisplay()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                if (_goldAmountText != null)
                    _goldAmountText.text = wallet.Gold.ToString();
                if (_diamondAmountText != null)
                    _diamondAmountText.text = wallet.Diamond.ToString();
            }
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            MoveTabIndicator(category);
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void MoveTabIndicator(ShopCategory category)
        {
            if (_tabIndicator == null || !_tabPositions.ContainsKey(category)) return;
            StartCoroutine(AnimateTabIndicator(_tabPositions[category]));
        }

        private IEnumerator AnimateTabIndicator(Vector3 targetPos)
        {
            Vector3 startPos = _tabIndicator.transform.localPosition;
            float duration = 0.2f;
            float elapsed = 0f;

            while (elapsed < duration)
            {
                elapsed += Time.deltaTime;
                float t = elapsed / duration;
                // ease-out
                t = 1f - (1f - t) * (1f - t);
                _tabIndicator.transform.localPosition = Vector3.Lerp(startPos, targetPos, t);
                yield return null;
            }

            _tabIndicator.transform.localPosition = targetPos;
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        /// <summary>
        /// 点击购买时，先弹出确认框
        /// </summary>
        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                ShowFeedback("已达购买上限!");
                return;
            }

            _pendingBuyItem = itemData;
            ShowConfirmDialog(itemData);
        }

        private void ShowConfirmDialog(ShopItemData itemData)
        {
            if (_confirmDialog == null)
            {
                // 没有确认弹窗则直接购买
                ExecuteBuy(itemData);
                return;
            }

            if (_confirmTitleText != null)
                _confirmTitleText.text = $"购买 {itemData.name}?";

            if (_confirmDescText != null)
            {
                string rewardText = ShopItemUI.BuildRewardText(itemData);
                _confirmDescText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : $"获得: {rewardText}";
            }

            if (_confirmPriceText != null)
            {
                int price = itemData.discount > 0
                    ? itemData.price * (100 - itemData.discount) / 100
                    : itemData.price;

                if (itemData.currencyType == CurrencyType.Free)
                {
                    _confirmPriceText.text = "免费领取";
                    _confirmPriceText.color = Color.green;
                }
                else
                {
                    string symbol = GetCurrencySymbol(itemData.currencyType);
                    _confirmPriceText.text = $"花费: {symbol} {price}";
                    _confirmPriceText.color = Color.white;
                }
            }

            _confirmDialog.SetActive(true);
        }

        private void OnConfirmBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);

            if (_pendingBuyItem != null)
            {
                ExecuteBuy(_pendingBuyItem);
                _pendingBuyItem = null;
            }
        }

        private void OnCancelBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            _pendingBuyItem = null;
        }

        private void ExecuteBuy(ShopItemData itemData)
        {
            int price = itemData.discount > 0
                ? itemData.price * (100 - itemData.discount) / 100
                : itemData.price;

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[ShopPanel] PlayerWallet not found");
                return;
            }

            bool success = itemData.currencyType switch
            {
                CurrencyType.Gold => wallet.SpendGold(price),
                CurrencyType.Diamond => wallet.SpendDiamond(price),
                CurrencyType.Free => true,
                _ => false
            };

            if (!success)
            {
                string curName = itemData.currencyType switch
                {
                    CurrencyType.Gold => "金币不足",
                    CurrencyType.Diamond => "钻石不足",
                    _ => "无法购买"
                };
                ShowFeedback(curName);
                return;
            }

            Debug.Log($"[ShopPanel] 购买成功: {itemData.name}, 花费: {price}");

            // 发放奖励
            if (itemData.rewardGold > 0)
                wallet.AddGold(itemData.rewardGold);
            if (itemData.rewardDiamond > 0)
                wallet.AddDiamond(itemData.rewardDiamond);
            if (itemData.rewardStamina > 0)
                wallet.AddStamina(itemData.rewardStamina);

            itemData.purchasedCount++;

            ShowFeedback($"购买成功! {itemData.name}");
            UpdateCurrencyDisplay();
            RefreshItemList();
        }

        private void ShowFeedback(string message)
        {
            if (_feedbackPanel == null || _feedbackText == null) return;

            if (_feedbackCoroutine != null)
                StopCoroutine(_feedbackCoroutine);

            _feedbackCoroutine = StartCoroutine(ShowFeedbackCoroutine(message));
        }

        private IEnumerator ShowFeedbackCoroutine(string message)
        {
            _feedbackPanel.SetActive(true);
            _feedbackText.text = message;

            // 淡入
            var canvasGroup = _feedbackPanel.GetComponent<CanvasGroup>();
            if (canvasGroup != null)
            {
                canvasGroup.alpha = 0f;
                float fadeIn = 0.2f;
                float t = 0f;
                while (t < fadeIn)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(0f, 1f, t / fadeIn);
                    yield return null;
                }
                canvasGroup.alpha = 1f;

                // 停留
                yield return new WaitForSeconds(_feedbackDuration);

                // 淡出
                float fadeOut = 0.3f;
                t = 0f;
                while (t < fadeOut)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(1f, 0f, t / fadeOut);
                    yield return null;
                }
                canvasGroup.alpha = 0f;
            }
            else
            {
                yield return new WaitForSeconds(_feedbackDuration);
            }

            _feedbackPanel.SetActive(false);
            _feedbackCoroutine = null;
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.Events;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.UI;

namespace TowerDefense.Tower
{
    /// <summary>
    /// 塔槽位组件 - 管理塔的放置、移除、升级和售卖
    /// </summary>
    public class TowerSlot : MonoBehaviour
    {
        [Header("Slot Settings")]
        [Tooltip("是否已被占用")]
        [SerializeField] private bool _isOccupied = false;

        [Tooltip("当前塔实例")]
        [SerializeField] private Tower _currentTower;

        [Tooltip("高亮效果物体")]
        [SerializeField] private GameObject _highlight;

        [Tooltip("建造指示器")]
        [SerializeField] private GameObject _buildIndicator;

        [Header("Slot Type")]
        [Tooltip("槽位类型")]
        [SerializeField] private LevelData.SlotType _slotType = LevelData.SlotType.Normal;

        [Header("Spawn Settings")]
        [Tooltip("塔的Z轴位置")]
        [SerializeField] private float _towerZPosition = -1f;

        [Tooltip("塔的缩放")]
        [SerializeField] private Vector3 _towerScale = Vector3.one;

        [Header("Build Button Settings")]
        [Tooltip("可以建造的塔列表")]
        [SerializeField] private TowerData[] buildableTowers;

        [Header("Events")]
        [Tooltip("塔放置事件")]
        public UnityEvent OnTowerPlaced;

        [Tooltip("塔移除事件")]
        [SerializeField] private UnityEvent OnTowerRemoved;

        [Tooltip("槽位选中事件")]
        public UnityEvent OnSlotSelected;

        /// <summary>
        /// 是否已被占用
        /// </summary>
        public bool IsOccupied => _isOccupied;

        /// <summary>
        /// 当前塔实例
        /// </summary>
        public Tower CurrentTower => _currentTower;

        /// <summary>
        /// 槽位类型
        /// </summary>
        public LevelData.SlotType SlotType => _slotType;

        /// <summary>
        /// 是否处于悬停状态
        /// </summary>
        private bool _isHovered = false;

        /// <summary>
        /// 是否处于选中状态
        /// </summary>
        private bool _isSelected = false;

        /// <summary>
        /// 初始化组件
        /// </summary>
        private void Awake()
        {
           // Debug.Log($"TowerSlot {gameObject.name} initialized");

            // 初始化高亮和建造指示器状态
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(!_isOccupied);
            }
        }

        /// <summary>
        /// 鼠标进入槽位
        /// </summary>
        private void OnMouseEnter()
        {
            if (!_isOccupied)
            {
                _isHovered = true;
                // Debug.Log($"Mouse entered slot: {gameObject.name}");

                // 显示高亮效果
                if (_highlight != null)
                {
                    _highlight.SetActive(true);
                }
            }
        }

        /// <summary>
        /// 鼠标离开槽位
        /// </summary>
        private void OnMouseExit()
        {
            _isHovered = false;
            // 非选中状态下隐藏高亮
            if (_highlight != null && !_isSelected)
            {
                _highlight.SetActive(false);
            }
        }

        void Start()
        {
            CircleCollider2D collider = GetComponent<CircleCollider2D>();
            if (collider != null)
            {
                collider.radius = 1f;
            }
        }

        /// <summary>
        /// 鼠标点击槽位
        /// </summary>
        private void OnMouseDown()
        {
            Debug.Log($"Slot clicked: {gameObject.name}, IsOccupied: {_isOccupied}");

            // 取消之前的选中状态（不隐藏面板，面板常驻）
            DeselectAllSlots();
            HideTowerInfoPanel();

            if (!_isOccupied)
            {
                SelectSlot();
                ShowTowerSelectPanel();
            }
            else
            {
                SelectSlot();
                ShowTowerInfoPanel();
            }
        }

        /// <summary>
        /// 选中槽位
        /// </summary>
        public void SelectSlot()
        {
            _isSelected = true;
            OnSlotSelected?.Invoke();
                // Debug.Log($"Slot selected: {gameObject.name}");

            // 如果有塔，显示攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.ShowRange();
            }
        }

        /// <summary>
        /// 取消选中槽位
        /// </summary>
        public void DeselectSlot()
        {
            _isSelected = false;
            // 隐藏高亮效果
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 如果有塔，隐藏攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.HideRange();
            }
                // Debug.Log($"Slot deselected: {gameObject.name}");
        }

        /// <summary>
        /// 显示塔选择面板
        /// </summary>
        private void ShowTowerSelectPanel()
        {
            // 先尝试通过 画布 下已知路径查找（包括非激活对象）
            TowerSelectPanel panel = null;
            var panelObj = GameObject.Find("画布/塔选择面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：用英文名查找（兼容重命名前）
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerSelectPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：在激活对象中查找
            if (panel == null)
            {
                panel = FindObjectOfType<TowerSelectPanel>();
            }

            if (panel != null)
            {
                panel.Show(this);
            }
        }

        /// <summary>
        /// 显示塔信息面板
        /// </summary>
        private void ShowTowerInfoPanel()
        {
            TowerInfoPanel panel = null;
            var panelObj = GameObject.Find("画布/塔信息面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerInfoPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panel = FindObjectOfType<TowerInfoPanel>();
            }
            if (panel != null && _currentTower != null)
            {
                panel.Show(_currentTower);
            }
        }

        /// <summary>
        /// 取消所有槽位的选中状态
        /// </summary>
        private void DeselectAllSlots()
        {
            foreach (var slot in FindObjectsOfType<TowerSlot>())
            {
                if (slot._isSelected)
                {
                    slot.DeselectSlot();
                }
            }
        }

        /// <summary>
        /// 隐藏塔信息面板
        /// </summary>
        private void HideTowerInfoPanel()
        {
            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }
        }

        /// <summary>
        /// 隐藏所有UI面板
        /// </summary>
        private void HideAllPanels()
        {
            var selectObj = GameObject.Find("画布/塔选择面板");
            if (selectObj == null) selectObj = GameObject.Find("Canvas/TowerSelectPanel");
            if (selectObj != null)
            {
                var selectPanel = selectObj.GetComponent<TowerSelectPanel>();
                if (selectPanel != null) selectPanel.Hide();
            }
            else
            {
                var sp = FindObjectOfType<TowerSelectPanel>();
                if (sp != null) sp.Hide();
            }

            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

        /// <summary>
        /// 被管理器调用的建造按钮点击
        /// </summary>
        public void OnBuildButtonClickedByManager()
        {
                // Debug.Log("OnBuildButtonClickedByManager called!");

            // 尝试放置塔
            TowerData towerToBuild = GetTowerDataToBuild();

            if (towerToBuild != null)
            {
                bool success = PlaceTower(towerToBuild);

                if (success)
                {
                    // Debug.Log("✅ Tower built successfully!");
                }
                else
                {
                    // Debug.Log("❌ Failed to build tower!");
                }
            }
            else
            {
                // Debug.LogError("❌ No tower data to build!");
            }
        }

        /// <summary>
        /// 获取要建造的塔数据
        /// </summary>
        private TowerData GetTowerDataToBuild()
        {
            // 优先使用配置的塔列表
            if (buildableTowers != null && buildableTowers.Length > 0)
            {
                    // Debug.Log($"Using configured tower: {buildableTowers[0].towerName}");
                return buildableTowers[0];
            }

            // 尝试从Resources/Data/Towers/加载
            Debug.Log("Trying to load from Resources/Data/Towers/");
            TowerData[] towerDatas1 = Resources.LoadAll<TowerData>("Data/Towers");
            if (towerDatas1.Length > 0)
            {
                     Debug.Log($"Found {towerDatas1.Length} tower data assets in Data/Towers/");
                return towerDatas1[0];
            }

            // 尝试从Resources/Data/加载
            Debug.Log("Trying to load from Resources/Data/");
            TowerData[] towerDatas2 = Resources.LoadAll<TowerData>("Data");
            if (towerDatas2.Length > 0)
            {
                Debug.Log($"Found {towerDatas2.Length} tower data assets in Data/");
                return towerDatas2[0];
            }

                Debug.LogError("❌ No tower data found!");
            return null;
        }

        /// <summary>
        /// 在槽位放置塔
        /// </summary>
        /// <param name="towerData">塔数据</param>
        /// <returns>是否放置成功</returns>
        public bool PlaceTower(TowerData towerData)
        {
            if (_isOccupied) return false;

            int cost = towerData.levels[0].cost;
            if (!GameManager.Instance.SpendGold(cost)) return false;

            Vector3 spawnPos = transform.position;
            spawnPos.z = _towerZPosition;

            GameObject towerObj = Instantiate(towerData.towerPrefab, spawnPos, Quaternion.identity);
            if (towerObj == null) return false;

            if (_towerScale != Vector3.one)
            {
                towerObj.transform.localScale = _towerScale;
            }

            _currentTower = towerObj.GetComponent<Tower>();
            if (_currentTower != null)
            {
                _currentTower.Initialize(towerData, this);
            }

            _isOccupied = true;

            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(false);
            }
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            OnTowerPlaced?.Invoke();
            EventBus.Publish(new TowerPlacedEvent { Tower = towerObj, Cost = cost });

            return true;
        }

        /// <summary>
        /// 移除塔（不返还金币）
        /// </summary>
        public void RemoveTower()
        {
            _currentTower = null;
            _isOccupied = false;

            // 显示建造指示器
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(true);
            }

            OnTowerRemoved?.Invoke();
        }

        /// <summary>
        /// 售卖塔（返还部分金币）
        /// </summary>
        public void SellTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Sell();
        }

        /// <summary>
        /// 升级塔
        /// </summary>
        public void UpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Upgrade();
        }

        /// <summary>
        /// 获取塔的售卖价值
        /// </summary>
        /// <returns>售卖金币数</returns>
        public int GetTowerSellValue()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetSellValue();
        }

        /// <summary>
        /// 获取塔的升级费用
        /// </summary>
        /// <returns>升级金币数</returns>
        public int GetTowerUpgradeCost()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetUpgradeCost();
        }

        /// <summary>
        /// 检查塔是否可以升级
        /// </summary>
        /// <returns>是否可升级</returns>
        public bool CanUpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return false;
            return !_currentTower.IsMaxLevel;
        }

        /// <summary>
        /// 绘制Gizmos（编辑器模式下）
        /// </summary>
        private void OnDrawGizmos()
        {
            // 绿色表示可建造，红色表示已占用
            Gizmos.color = _isOccupied ? Color.red : Color.green;
            Gizmos.DrawWireSphere(transform.position, 0.3f);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerInfoPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;

        [Header("Tower Info")]
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Text _attackSpeedText;

        [Header("Buttons")]
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;
        [SerializeField] private Button _closeButton;

        private TowerDefense.Tower.Tower _currentTower;

        private void Awake()
        {
            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }

            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }

            if (_closeButton != null)
            {
                _closeButton.onClick.AddListener(Hide);
            }
        }

        public void Show(TowerDefense.Tower.Tower tower)
        {
            _currentTower = tower;

            UpdateTowerInfo();

            if (_panel != null)
            {
                _panel.SetActive(true);
            }

            tower.OnUpgrade += OnTowerUpgraded;
            tower.OnSell += OnTowerSold;
        }

        public void Hide()
        {
            if (_currentTower != null)
            {
                _currentTower.OnUpgrade -= OnTowerUpgraded;
                _currentTower.OnSell -= OnTowerSold;
            }

            _currentTower = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_currentTower == null) return;

            var data = _currentTower.Data;
            var stats = _currentTower.CurrentStats;

            if (_towerNameText != null)
            {
                _towerNameText.text = data.towerName;
            }

            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"等级 {_currentTower.CurrentLevel}/{data.levels.Length}";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"攻击范围: {stats.attackRange}";
            }

            if (_attackSpeedText != null)
            {
                _attackSpeedText.text = $"攻击速度: {stats.attackSpeed:0.0}";
            }

            UpdateUpgradeButton();
            UpdateSellButton();
        }

        private void UpdateUpgradeButton()
        {
            if (_upgradeButton == null || _upgradeCostText == null) return;

            if (_currentTower.IsMaxLevel)
            {
                _upgradeButton.interactable = false;
                _upgradeCostText.text = "已满级";
                _upgradeCostText.color = Color.grey;
            }
            else
            {
                int upgradeCost = _currentTower.GetUpgradeCost();
                bool canAfford = GameManager.Instance.HasEnoughGold(upgradeCost);

                _upgradeButton.interactable = canAfford;
                _upgradeCostText.text = $"升级（{upgradeCost}金币）";
                _upgradeCostText.color = canAfford ? Color.yellow : Color.red;
            }
        }

        private void UpdateSellButton()
        {
            if (_sellValueText == null) return;

            int sellValue = _currentTower.GetSellValue();
            _sellValueText.text = $"出售（{sellValue}金币）";
        }

        private void OnUpgradeClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Upgrade();
            }
        }

        private void OnSellClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Sell();
            }
        }

        private void OnTowerUpgraded(TowerDefense.Tower.Tower tower)
        {
            UpdateTowerInfo();
        }

        private void OnTowerSold(TowerDefense.Tower.Tower tower)
        {
            Hide();
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            if (_panel != null && _panel.activeSelf && _currentTower != null)
            {
                UpdateUpgradeButton();
            }
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源建筑，自动产出资源。
    /// </summary>
    public class ResourceBuilding : BuildingBase
    {
        private float _accumulated;

        protected override void BuildingUpdate()
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen)
                return;

            var levelData = CurrentLevelData;
            if (levelData.productionRate <= 0) return;

            _productionTimer += Time.deltaTime;
            float interval = 1f / levelData.productionRate;

            if (_productionTimer >= interval)
            {
                _productionTimer -= interval;
                _accumulated++;

                if (_accumulated >= levelData.productionCapacity)
                {
                    CollectResources();
                }
            }
        }

        /// <summary>
        /// 收集已产出的资源。
        /// </summary>
        public int CollectResources()
        {
            int collected = (int)_accumulated;
            if (collected <= 0) return 0;

            _accumulated = 0;

            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                switch (_data.producedResource)
                {
                    case ResourceType.Gold:
                        profile.AddGold(collected, "home_resource");
                        break;
                    case ResourceType.Diamond:
                        profile.AddDiamond(collected, "home_resource");
                        break;
                }
            }

            Debug.Log($"[ResourceBuilding] 收集 {collected} {_data.producedResource} from {_data.buildingName}");
            return collected;
        }

        /// <summary>
        /// 计算离线收益。
        /// </summary>
        public int CalculateOfflineEarnings(float offlineSeconds)
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen) return 0;
            var levelData = CurrentLevelData;
            return Mathf.FloorToInt(levelData.productionRate * offlineSeconds);
        }

        protected override void OnUpgraded()
        {
            // 升级后立即收集一次
            CollectResources();
        }
    }
}

