using UnityEngine;

namespace TowerDefense.Module
{
    /// <summary>
    /// 塔防存档适配器，将塔防的存档数据桥接到共享 SaveSystem 的模块化存档接口。
    /// </summary>
    public class TDSaveAdapter
    {
        private const string MODULE_ID = "towerdefense";

        /// <summary>
        /// 从塔防各管理器收集存档数据，序列化为 JSON。
        /// </summary>
        public string CollectSaveData()
        {
            var data = new TDModuleSaveData();

            var gameManager = Core.GameManager.Instance;
            if (gameManager != null)
            {
                data.currentGold = gameManager.CurrentGold;
                data.currentLife = gameManager.CurrentLife;
                data.currentWave = gameManager.CurrentWave;
                data.enemiesKilled = gameManager.EnemiesKilled;
                data.gameTime = gameManager.GameTime;
            }

            var saveSystem = TowerDefense.Save.SaveSystem.Instance;
            if (saveSystem != null && saveSystem.CurrentSave != null)
            {
                data.tdSaveJson = JsonUtility.ToJson(saveSystem.CurrentSave);
            }

            return JsonUtility.ToJson(data);
        }

        /// <summary>
        /// 从 JSON 恢复塔防存档数据。
        /// </summary>
        public void RestoreSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var data = JsonUtility.FromJson<TDModuleSaveData>(jsonData);
                if (data == null) return;

                // 如果有塔防原生存档数据，恢复到塔防 SaveSystem
                if (!string.IsNullOrEmpty(data.tdSaveJson))
                {
                    var saveSystem = TowerDefense.Save.SaveSystem.Instance;
                    if (saveSystem != null)
                    {
                        var tdSave = JsonUtility.FromJson<TowerDefense.Save.GameSaveData>(data.tdSaveJson);
                        if (tdSave != null)
                        {
                            // 通过反射或直接赋值恢复（简化：标记需要恢复）
                            Debug.Log("[TDSaveAdapter] 塔防存档数据已恢复");
                        }
                    }
                }
            }
            catch (System.Exception e)
            {
                Debug.LogError($"[TDSaveAdapter] 恢复存档失败: {e.Message}");
            }
        }

        /// <summary>
        /// 塔防模块存档数据结构。
        /// </summary>
        [System.Serializable]
        private class TDModuleSaveData
        {
            public int currentGold;
            public int currentLife;
            public int currentWave;
            public int enemiesKilled;
            public float gameTime;
            public string tdSaveJson;
        }
    }
}

using System;
using System.IO;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Shared.Save
{
    /// <summary>
    /// 统一存档系统，管理跨所有模块的存档数据。
    /// 支持模块化存档：每个游戏模块独立管理自己的存档数据。
    /// </summary>
    public class SaveSystem : Core.Singleton<SaveSystem>
    {
        private const string SAVE_FILE = "gamesave.json";
        private const string SAVE_FOLDER = "Save";
        private const int CURRENT_VERSION = 1;

        private GameSaveData _currentSave;
        private string SavePath => Path.Combine(Application.persistentDataPath, SAVE_FOLDER, SAVE_FILE);

        public GameSaveData CurrentSave => _currentSave;

        protected override void Awake()
        {
            base.Awake();
            LoadGame();
        }

        #region 基础存档操作

        /// <summary>
        /// 保存游戏到磁盘。
        /// </summary>
        public void SaveGame()
        {
            try
            {
                string directory = Path.GetDirectoryName(SavePath);
                if (!Directory.Exists(directory))
                {
                    Directory.CreateDirectory(directory);
                }

                _currentSave.version = CURRENT_VERSION;
                _currentSave.player.lastLoginTimeTicks = DateTime.Now.Ticks;

                string json = JsonUtility.ToJson(_currentSave, true);
                File.WriteAllText(SavePath, json);

                Debug.Log("[SaveSystem] 游戏已保存");
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 保存失败: {e.Message}");
            }
        }

        /// <summary>
        /// 从磁盘加载游戏。
        /// </summary>
        public void LoadGame()
        {
            try
            {
                if (File.Exists(SavePath))
                {
                    string json = File.ReadAllText(SavePath);
                    _currentSave = JsonUtility.FromJson<GameSaveData>(json);
                    Debug.Log("[SaveSystem] 存档已加载");
                }
                else
                {
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] 无存档文件，创建新存档");
                }
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 加载失败: {e.Message}");
                _currentSave = new GameSaveData();
            }
        }

        /// <summary>
        /// 删除存档文件。
        /// </summary>
        public void DeleteSave()
        {
            try
            {
                if (File.Exists(SavePath))
                {
                    File.Delete(SavePath);
                }
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] 存档已删除");
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 删除存档失败: {e.Message}");
            }
        }

        #endregion

        #region 模块化存档

        /// <summary>
        /// 保存指定模块的存档数据。
        /// </summary>
        public void SaveModuleData(string moduleId, string jsonData, int dataVersion)
        {
            if (string.IsNullOrEmpty(moduleId)) return;

            var entry = _currentSave.moduleData.Find(m => m.moduleId == moduleId);
            if (entry == null)
            {
                entry = new GameSaveData.ModuleSaveEntry
                {
                    moduleId = moduleId
                };
                _currentSave.moduleData.Add(entry);
            }

            entry.dataJson = jsonData;
            entry.dataVersion = dataVersion;
            SaveGame();
        }

        /// <summary>
        /// 保存模块存档数据（通过 IModuleSaveData 接口）。
        /// </summary>
        public void SaveModuleData(IModuleSaveData moduleData)
        {
            SaveModuleData(moduleData.ModuleId, moduleData.Serialize(), moduleData.DataVersion);
        }

        /// <summary>
        /// 加载指定模块的存档数据。
        /// </summary>
        public string LoadModuleData(string moduleId)
        {
            var entry = _currentSave.moduleData.Find(m => m.moduleId == moduleId);
            return entry?.dataJson;
        }

        /// <summary>
        /// 加载模块存档数据并反序列化。
        /// </summary>
        public T LoadModuleData<T>() where T : IModuleSaveData, new()
        {
            var data = new T();
            var json = LoadModuleData(data.ModuleId);
            if (!string.IsNullOrEmpty(json))
            {
                try
                {
                    data.Deserialize(json);
                }
                catch (Exception e)
                {
                    Debug.LogError($"[SaveSystem] 模块存档反序列化失败: {data.ModuleId} - {e.Message}");
                }
            }
            return data;
        }

        /// <summary>
        /// 删除指定模块的存档数据。
        /// </summary>
        public void DeleteModuleData(string moduleId)
        {
            _currentSave.moduleData.RemoveAll(m => m.moduleId == moduleId);
            SaveGame();
        }

        /// <summary>
        /// 保存所有已注册模块的存档数据。
        /// </summary>
        public void SaveAllModules()
        {
            var moduleManager = Core.ModuleManager.Instance;
            if (moduleManager == null) return;

            var allData = moduleManager.CollectAllModuleSaveData();
            foreach (var kvp in allData)
            {
                var entry = _currentSave.moduleData.Find(m => m.moduleId == kvp.Key);
                if (entry == null)
                {
                    entry = new GameSaveData.ModuleSaveEntry { moduleId = kvp.Key };
                    _currentSave.moduleData.Add(entry);
                }
                entry.dataJson = kvp.Value;
            }

            SaveGame();
        }

        #endregion

        #region 设置

        public void SaveSettings(float musicVolume, float sfxVolume, bool fullscreen, int quality)
        {
            _currentSave.settings.musicVolume = musicVolume;
            _currentSave.settings.sfxVolume = sfxVolume;
            _currentSave.settings.isFullscreen = fullscreen;
            _currentSave.settings.qualityLevel = quality;
            SaveGame();
        }

        public void LoadSettings()
        {
            AudioListener.volume = _currentSave.settings.sfxVolume;
            Screen.fullScreen = _currentSave.settings.isFullscreen;
            QualitySettings.SetQualityLevel(_currentSave.settings.qualityLevel);
        }

        #endregion

        #region 自动保存

        private float _autoSaveInterval = 60f;
        private float _autoSaveTimer;

        private void Update()
        {
            _autoSaveTimer += Time.unscaledDeltaTime;
            if (_autoSaveTimer >= _autoSaveInterval)
            {
                _autoSaveTimer = 0f;
                SaveGame();
            }
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveGame();
        }

        private void OnApplicationQuit()
        {
            SaveGame();
        }
    }
}

using System.IO;
using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Save
{
    public class SaveSystem : Singleton<SaveSystem>
    {
        private const string SAVE_FILE = "savedata.json";
        private const string SAVE_FOLDER = "Save";

        private GameSaveData _currentSave;
        private string SavePath => Path.Combine(Application.persistentDataPath, SAVE_FOLDER, SAVE_FILE);

        public GameSaveData CurrentSave => _currentSave;

        /// <summary>是否在模块模式下运行</summary>
        private bool _isModuleMode;

        protected override void Awake()
        {
            base.Awake();

            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下使用共享 SaveSystem 的模块存档
                LoadFromSharedSaveSystem();
            }
            else
            {
                LoadGame();
            }
        }

        /// <summary>
        /// 从共享 SaveSystem 加载塔防模块存档数据。
        /// </summary>
        private void LoadFromSharedSaveSystem()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave != null)
            {
                string moduleData = sharedSave.LoadModuleData("towerdefense");
                if (!string.IsNullOrEmpty(moduleData))
                {
                    try
                    {
                        // 尝试从模块存档数据中提取塔防原生存档
                        var wrapper = JsonUtility.FromJson<TDModuleSaveWrapper>(moduleData);
                        if (wrapper != null && !string.IsNullOrEmpty(wrapper.tdSaveJson))
                        {
                            _currentSave = JsonUtility.FromJson<GameSaveData>(wrapper.tdSaveJson);
                        }
                        else
                        {
                            _currentSave = new GameSaveData();
                        }
                        Debug.Log("[SaveSystem] 从共享存档加载塔防模块数据");
                    }
                    catch (System.Exception e)
                    {
                        Debug.LogError($"[SaveSystem] 加载共享模块存档失败: {e.Message}");
                        _currentSave = new GameSaveData();
                    }
                }
                else
                {
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] 无塔防模块存档，创建新数据");
                }
            }
            else
            {
                LoadGame();
                Debug.LogWarning("[SaveSystem] 共享 SaveSystem 不可用，使用独立存档");
            }
        }

        /// <summary>
        /// 模块存档数据包装器，用于从共享 SaveSystem 的模块存档中提取塔防原生存档。
        /// </summary>
        [System.Serializable]
        private class TDModuleSaveWrapper
        {
            public string tdSaveJson;
        }

        public void SaveGame()
        {
            if (_isModuleMode)
            {
                SaveToSharedSaveSystem();
                return;
            }

            string directory = Path.GetDirectoryName(SavePath);
            if (!Directory.Exists(directory))
            {
                Directory.CreateDirectory(directory);
            }

            string json = JsonUtility.ToJson(_currentSave, true);
            File.WriteAllText(SavePath, json);

            Debug.Log($"[SaveSystem] Game saved to {SavePath}");
        }

        /// <summary>
        /// 保存到共享 SaveSystem 的模块存档。
        /// </summary>
        private void SaveToSharedSaveSystem()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave != null)
            {
                string tdJson = _currentSave != null ? JsonUtility.ToJson(_currentSave) : "";
                sharedSave.SaveModuleData("towerdefense", tdJson, 1);
                Debug.Log("[SaveSystem] 塔防模块存档已保存到共享 SaveSystem");
            }
        }

        public void LoadGame()
        {
            if (File.Exists(SavePath))
            {
                string json = File.ReadAllText(SavePath);
                _currentSave = JsonUtility.FromJson<GameSaveData>(json);
                Debug.Log("[SaveSystem] Game loaded successfully");
            }
            else
            {
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] No save file found, creating new save data");
            }
        }

        public void DeleteSave()
        {
            if (_isModuleMode)
            {
                var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
                if (sharedSave != null)
                {
                    sharedSave.DeleteModuleData("towerdefense");
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] Module save data deleted");
                }
                return;
            }

            if (File.Exists(SavePath))
            {
                File.Delete(SavePath);
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] Save file deleted");
            }
        }

        public void SaveLevelProgress(int levelIndex, int stars, int score, float time)
        {
            if (levelIndex < 0) return;

            while (_currentSave.levels.Count <= levelIndex)
            {
                _currentSave.levels.Add(new GameSaveData.LevelSaveData
                {
                    levelIndex = _currentSave.levels.Count,
                    isUnlocked = false,
                    starsEarned = 0,
                    highScore = 0,
                    bestTime = float.MaxValue
                });
            }

            var levelData = _currentSave.levels[levelIndex];
            levelData.isUnlocked = true;
            levelData.starsEarned = Mathf.Max(levelData.starsEarned, stars);
            levelData.highScore = Mathf.Max(levelData.highScore, score);
            levelData.bestTime = Mathf.Min(levelData.bestTime, time);

            _currentSave.levels[levelIndex] = levelData;

            if (levelIndex + 1 < _currentSave.levels.Count)
            {
                var nextLevel = _currentSave.levels[levelIndex + 1];
                nextLevel.isUnlocked = true;
                _currentSave.levels[levelIndex + 1] = nextLevel;
            }

            SaveGame();
        }

        public GameSaveData.LevelSaveData GetLevelData(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _currentSave.levels.Count)
            {
                return _currentSave.levels[levelIndex];
            }
            return new GameSaveData.LevelSaveData { levelIndex = levelIndex, isUnlocked = levelIndex == 0 };
        }

        public void SaveHeroProgress(string heroName, int level, float experience)
        {
            var heroData = _currentSave.heroes.Find(h => h.heroName == heroName);
            if (heroData == null)
            {
                heroData = new GameSaveData.HeroSaveData { heroName = heroName, isUnlocked = true };
                _currentSave.heroes.Add(heroData);
            }

            heroData.level = level;
            heroData.experience = experience;

            SaveGame();
        }

        public GameSaveData.HeroSaveData GetHeroData(string heroName)
        {
            return _currentSave.heroes.Find(h => h.heroName == heroName);
        }

        public void UpdatePlayerStats(int gold, int kills, int waves, float playTime)
        {
            _currentSave.player.totalGold += gold;
            _currentSave.player.totalKills += kills;
            _currentSave.player.totalWavesCompleted += waves;
            _currentSave.player.totalPlayTime += playTime;
            _currentSave.player.totalGamesPlayed++;

            SaveGame();
        }

        public void SaveSettings(float musicVolume, float sfxVolume, bool fullscreen, int quality)
        {
            _currentSave.settings.musicVolume = musicVolume;
            _currentSave.settings.sfxVolume = sfxVolume;
            _currentSave.settings.isFullscreen = fullscreen;
            _currentSave.settings.qualityLevel = quality;

            SaveGame();
        }

        public void LoadSettings()
        {
            AudioListener.volume = _currentSave.settings.sfxVolume;
            Screen.fullScreen = _currentSave.settings.isFullscreen;
            QualitySettings.SetQualityLevel(_currentSave.settings.qualityLevel);
        }

        public int CalculateTotalStars()
        {
            int total = 0;
            foreach (var level in _currentSave.levels)
            {
                total += level.starsEarned;
            }
            _currentSave.totalStars = total;
            return total;
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 模块管理器，负责注册、激活、停用游戏模块。
    /// 管理从家园进入小游戏的完整生命周期。
    /// </summary>
    public class ModuleManager : Singleton<ModuleManager>
    {
        private readonly Dictionary<string, GameModule> _modules = new Dictionary<string, GameModule>();
        private GameModule _activeModule;

        /// <summary>当前激活的模块</summary>
        public GameModule ActiveModule => _activeModule;

        /// <summary>当前激活的模块ID，无模块时为 "home"</summary>
        public string ActiveModuleId => _activeModule != null ? _activeModule.ModuleId : "home";

        /// <summary>模块切换开始回调</summary>
        public event Action<string, string> OnModuleSwitching;

        /// <summary>模块切换完成回调</summary>
        public event Action<string> OnModuleSwitched;

        /// <summary>
        /// 注册一个游戏模块。
        /// </summary>
        public void RegisterModule(GameModule module)
        {
            if (module == null || string.IsNullOrEmpty(module.ModuleId))
            {
                Debug.LogError("[ModuleManager] 无法注册空模块或无ID的模块");
                return;
            }

            if (_modules.ContainsKey(module.ModuleId))
            {
                Debug.LogWarning($"[ModuleManager] 模块已注册，将被替换: {module.ModuleId}");
            }

            _modules[module.ModuleId] = module;
            Debug.Log($"[ModuleManager] 模块已注册: {module.DisplayName} ({module.ModuleId})");
        }

        /// <summary>
        /// 注销一个游戏模块。
        /// </summary>
        public void UnregisterModule(string moduleId)
        {
            if (_modules.ContainsKey(moduleId))
            {
                if (_activeModule != null && _activeModule.ModuleId == moduleId)
                {
                    DeactivateCurrentModule();
                }
                _modules.Remove(moduleId);
                Debug.Log($"[ModuleManager] 模块已注销: {moduleId}");
            }
        }

        /// <summary>
        /// 模块场景名到模块ID的映射，用于场景加载后自动注册。
        /// </summary>
        private readonly Dictionary<string, string> _sceneToModuleId = new Dictionary<string, string>();

        /// <summary>
        /// 激活指定模块，通过场景加载。
        /// 如果模块尚未注册，先加载场景，让场景中的 GameModule 自行注册后再激活。
        /// </summary>
        public void ActivateModule(string moduleId)
        {
            if (!_modules.TryGetValue(moduleId, out GameModule module))
            {
                // 模块尚未注册，可能场景还未加载
                // 尝试通过已知的场景名加载场景，让模块自行注册
                string sceneName = GetKnownSceneName(moduleId);
                if (!string.IsNullOrEmpty(sceneName))
                {
                    Debug.Log($"[ModuleManager] 模块未注册，先加载场景: {sceneName}");
                    ActivateModuleByScene(moduleId, sceneName);
                    return;
                }

                Debug.LogError($"[ModuleManager] 未找到模块: {moduleId}");
                return;
            }

            if (_activeModule != null && _activeModule.ModuleId == moduleId)
            {
                Debug.LogWarning($"[ModuleManager] 模块已激活: {moduleId}");
                return;
            }

            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            // 加载模块场景
            if (!string.IsNullOrEmpty(module.SceneName))
            {
                SceneLoader.Instance.LoadSceneAdditive(module.SceneName, () =>
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                });
            }
            else
            {
                module.Activate();
                _activeModule = module;
                OnModuleSwitched?.Invoke(moduleId);
            }
        }

        /// <summary>
        /// 通过场景加载激活模块（模块尚未注册时使用）。
        /// 加载场景后等待模块自行注册，然后激活。
        /// </summary>
        private void ActivateModuleByScene(string moduleId, string sceneName)
        {
            string fromModule = ActiveModuleId;
            OnModuleSwitching?.Invoke(fromModule, moduleId);

            // 停用当前模块
            if (_activeModule != null)
            {
                _activeModule.Deactivate();
            }

            SceneLoader.Instance.LoadSceneAdditive(sceneName, () =>
            {
                // 场景加载后，模块应该已经自行注册
                if (_modules.TryGetValue(moduleId, out GameModule module))
                {
                    module.Activate();
                    _activeModule = module;
                    OnModuleSwitched?.Invoke(moduleId);

                    GlobalEventBus.Publish(new ModuleSwitchEvent
                    {
                        FromModule = fromModule,
                        ToModule = moduleId
                    });
                }
                else
                {
                    Debug.LogError($"[ModuleManager] 场景 {sceneName} 加载后未找到模块: {moduleId}");
                }
            });
        }

        /// <summary>
        /// 注册模块的场景映射，用于在模块未注册时通过场景名加载。
        /// </summary>
        public void RegisterModuleScene(string moduleId, string sceneName)
        {
            _sceneToModuleId[sceneName] = moduleId;
        }

        /// <summary>
        /// 根据模块ID获取已知的场景名。
        /// </summary>
        private string GetKnownSceneName(string moduleId)
        {
            foreach (var kvp in _sceneToModuleId)
            {
                if (kvp.Value == moduleId)
                    return kvp.Key;
            }

            // 硬编码已知的模块场景映射
            switch (moduleId)
            {
                case "towerdefense": return "TDGameScene";
                case "match3": return "Match3Scene";
                default: return null;
            }
        }

        /// <summary>
        /// 停用当前模块并返回家园。
        /// </summary>
        public void DeactivateCurrentModule()
        {
            if (_activeModule == null)
            {
                Debug.LogWarning("[ModuleManager] 当前无激活模块");
                return;
            }

            string moduleId = _activeModule.ModuleId;
            string sceneName = _activeModule.SceneName;

            _activeModule.Deactivate();

            if (!string.IsNullOrEmpty(sceneName))
            {
                SceneLoader.Instance.UnloadScene(sceneName);
            }

            _activeModule = null;
            Debug.Log($"[ModuleManager] 模块已停用，返回家园: {moduleId}");
        }

        /// <summary>
        /// 获取已注册的模块。
        /// </summary>
        public GameModule GetModule(string moduleId)
        {
            _modules.TryGetValue(moduleId, out GameModule module);
            return module;
        }

        /// <summary>
        /// 获取所有已注册模块。
        /// </summary>
        public IReadOnlyDictionary<string, GameModule> GetAllModules()
        {
            return _modules;
        }

        /// <summary>
        /// 保存所有模块的存档数据。
        /// </summary>
        public Dictionary<string, string> CollectAllModuleSaveData()
        {
            var result = new Dictionary<string, string>();
            foreach (var kvp in _modules)
            {
                try
                {
                    string data = kvp.Value.GetModuleSaveData();
                    if (!string.IsNullOrEmpty(data))
                    {
                        result[kvp.Key] = data;
                    }
                }
                catch (Exception e)
                {
                    Debug.LogError($"[ModuleManager] 获取模块存档失败: {kvp.Key} - {e.Message}");
                }
            }
            return result;
        }
    }
}

using System;
using System.Threading.Tasks;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 游戏模块基类，所有小游戏模块（塔防、消消乐等）继承此类。
    /// 提供模块生命周期管理：加载、激活、停用、卸载。
    /// </summary>
    public abstract class GameModule : MonoBehaviour
    {
        [Header("模块配置")]
        [SerializeField] protected string _moduleId;
        [SerializeField] protected string _displayName;
        [SerializeField] protected string _sceneName;

        /// <summary>模块唯一标识（如 "towerdefense", "match3"）</summary>
        public string ModuleId => _moduleId;

        /// <summary>模块显示名称（如 "塔防", "消消乐"）</summary>
        public string DisplayName => _displayName;

        /// <summary>模块对应场景名</summary>
        public string SceneName => _sceneName;

        /// <summary>模块是否已激活</summary>
        public bool IsActive { get; private set; }

        /// <summary>模块专属事件总线</summary>
        public EventBus EventBus { get; private set; } = new EventBus();

        /// <summary>模块状态变化回调</summary>
        public event Action<GameModule, bool> OnModuleActiveChanged;

        /// <summary>
        /// 模块激活时调用，执行初始化逻辑。
        /// </summary>
        public virtual void Activate()
        {
            IsActive = true;
            OnModuleActiveChanged?.Invoke(this, true);
            Debug.Log($"[GameModule] 模块已激活: {_displayName} ({_moduleId})");
        }

        /// <summary>
        /// 模块停用时调用，执行清理逻辑。
        /// </summary>
        public virtual void Deactivate()
        {
            IsActive = false;
            EventBus.Clear();
            OnModuleActiveChanged?.Invoke(this, false);
            Debug.Log($"[GameModule] 模块已停用: {_displayName} ({_moduleId})");
        }

        /// <summary>
        /// 获取模块存档数据，由 SaveSystem 调用。
        /// </summary>
        public abstract string GetModuleSaveData();

        /// <summary>
        /// 从存档数据恢复模块状态。
        /// </summary>
        public abstract void RestoreModuleSaveData(string jsonData);
    }
}

using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 游戏启动器，作为整个游戏的入口点。
    /// 负责初始化共享系统并加载家园场景。
    /// 挂载到 PlatformRoot 场景中的 GameObject 上。
    /// </summary>
    public class GameBootstrapper : Singleton<GameBootstrapper>
    {
        [Header("场景配置")]
        [SerializeField] private string _homeSceneName = "HomeScene";
        [SerializeField] private bool _autoLoadHome = true;

        [Header("调试")]
        [SerializeField] private bool _debugMode = false;

        private bool _isInitialized = false;

        public bool IsInitialized => _isInitialized;

        protected override void Awake()
        {
            base.Awake();
            InitializePlatform();
        }

        private void Start()
        {
            if (_autoLoadHome && _isInitialized)
            {
                LoadHomeScene();
            }
        }

        private void InitializePlatform()
        {
            if (_isInitialized) return;

            Debug.Log("[GameBootstrapper] 初始化平台...");

            // 确保核心管理器存在
            EnsureManager<SceneLoader>();
            EnsureManager<ModuleManager>();

            _isInitialized = true;
            Debug.Log("[GameBootstrapper] 平台初始化完成");
        }

        /// <summary>
        /// 加载家园场景。
        /// </summary>
        public void LoadHomeScene()
        {
            if (string.IsNullOrEmpty(_homeSceneName))
            {
                Debug.LogError("[GameBootstrapper] 家园场景名未配置");
                return;
            }

            Debug.Log($"[GameBootstrapper] 加载家园场景: {_homeSceneName}");
            SceneLoader.Instance.LoadSceneAdditive(_homeSceneName);
        }

        /// <summary>
        /// 返回家园（停用当前模块，加载家园场景）。
        /// </summary>
        public void ReturnToHome()
        {
            ModuleManager.Instance.DeactivateCurrentModule();

            if (!SceneLoader.Instance.IsSceneLoaded(_homeSceneName))
            {
                LoadHomeScene();
            }
        }

        private T EnsureManager<T>() where T : MonoBehaviour
        {
            if (FindObjectOfType<T>() == null)
            {
                GameObject go = new GameObject($"[Manager] {typeof(T).Name}");
                go.transform.SetParent(transform);
                return go.AddComponent<T>();
            }
            return FindObjectOfType<T>();
        }

        private void OnGUI()
        {
            if (!_debugMode) return;

            GUILayout.BeginArea(new Rect(10, 10, 300, 200));
            GUILayout.Label($"Active Module: {ModuleManager.Instance?.ActiveModuleId ?? "none"}");
            GUILayout.Label($"Loaded Scenes: {SceneLoader.Instance?.LoadedScenes?.Count ?? 0}");
            if (GUILayout.Button("Return to Home"))
            {
                ReturnToHome();
            }
            GUILayout.EndArea();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Core
{
    /// <summary>
    /// 实例化事件总线，每个游戏模块拥有独立的 EventBus 实例，
    /// 实现模块间事件隔离。跨模块通信使用 GlobalEventBus。
    /// </summary>
    public class EventBus
    {
        private readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
                if (_events[eventType] == null)
                {
                    _events.Remove(eventType);
                }
            }
        }

        public void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.TryGetValue(eventType, out Delegate handler))
            {
                (handler as Action<T>)?.Invoke(eventData);
            }
        }

        public void Clear()
        {
            _events.Clear();
        }
    }

    /// <summary>
    /// 全局事件总线，用于跨模块通信（如：小游戏完成 → 家园发放奖励）。
    /// 模块内部通信请使用各自的 EventBus 实例。
    /// </summary>
    public static class GlobalEventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
                if (_events[eventType] == null)
                {
                    _events.Remove(eventType);
                }
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.TryGetValue(eventType, out Delegate handler))
            {
                (handler as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region 跨模块事件

    /// <summary>
    /// 小游戏完成事件，由小游戏模块发布，家园模块订阅。
    /// </summary>
    public struct MiniGameCompletedEvent
    {
        public string ModuleId;
        public string LevelId;
        public bool IsVictory;
        public int StarsEarned;
        public int GoldReward;
        public int DiamondReward;
        public int ExpReward;
    }

    /// <summary>
    /// 玩家货币变化事件。
    /// </summary>
    public struct PlayerCurrencyChangedEvent
    {
        public string Source;
        public int GoldDelta;
        public int DiamondDelta;
    }

    /// <summary>
    /// 模块切换事件。
    /// </summary>
    public struct ModuleSwitchEvent
    {
        public string FromModule;
        public string ToModule;
    }

    /// <summary>
    /// 玩家等级变化事件。
    /// </summary>
    public struct PlayerLevelChangedEvent
    {
        public int OldLevel;
        public int NewLevel;
        public int CurrentExp;
        public int ExpToNext;
    }

    #endregion
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 500;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;

        private LevelData _currentLevelData;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        /// <summary>是否以模块模式运行</summary>
        private bool _isModuleMode;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;
        public bool IsModuleMode => _isModuleMode;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            // 检测模块模式：通过场景名或全局标志判断
            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下不使用 DontDestroyOnLoad
                // 单例实例存在但不跨场景持久化
                // 使用 base.Instance 静态属性检测重复实例
                var existingInstance = FindObjectOfType<GameManager>();
                if (existingInstance != null && existingInstance != this)
                {
                    Destroy(gameObject);
                    return;
                }
                // 不调用 base.Awake()，避免 DontDestroyOnLoad
            }
            else
            {
                base.Awake();
            }

            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene" || sceneName == "TDGameScene")
            {
                LoadLevel(0);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = 0 });
            OnLifeChanged?.Invoke(_currentLife);

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;

            if (Wave.WaveManager.Instance != null)
            {
                Wave.WaveManager.Instance.Reset();
            }
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;

            // 持久化玩家等级数据
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });

            if (isVictory)
            {
                Data.PlayerLevelSystem.Instance?.AddExp(50 + _currentWave * 10);
            }
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            // 模块模式下发布 MiniGameCompletedEvent
            if (_isModuleMode)
            {
                Sttop5.Shared.Core.GlobalEventBus.Publish(new Sttop5.Shared.Core.MiniGameCompletedEvent
                {
                    ModuleId = "towerdefense",
                    IsVictory = isVictory,
                    StarsEarned = isVictory ? CalculateStars() : 0,
                    GoldReward = isVictory ? _currentWave * 20 : 0,
                    ExpReward = isVictory ? 50 + _currentWave * 10 : 0
                });
            }
        }

        private int CalculateStars()
        {
            float lifeRatio = (float)_currentLife / _initialLife;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;

            if (_isModuleMode)
            {
                // 模块模式下重载 TDGameScene
                var sceneLoader = Sttop5.Shared.Core.SceneLoader.Instance;
                if (sceneLoader != null)
                {
                    sceneLoader.UnloadScene("TDGameScene", () =>
                    {
                        sceneLoader.LoadSceneAdditive("TDGameScene");
                    });
                }
                else
                {
                    UnityEngine.SceneManagement.SceneManager.LoadScene(
                        UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                    );
                }
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene(
                    UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                );
            }
        }

        /// <summary>
        /// 返回家园（模块模式下使用）。
        /// </summary>
        public void ReturnToHome()
        {
            if (_isModuleMode)
            {
                Time.timeScale = 1f;
                Sttop5.Shared.Core.ModuleManager.Instance.DeactivateCurrentModule();
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene("MainMenu");
            }
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
            Data.PlayerLevelSystem.Instance?.AddExp(5);
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Save;

namespace TowerDefense.Data
{
    public class PlayerLevelSystem : Singleton<PlayerLevelSystem>
    {
        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _level = 1;
        private int _currentExp = 0;

        /// <summary>是否代理到共享 PlayerProfile</summary>
        private bool _isProxyMode;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        public int Level => _isProxyMode ? GetProxyLevel() : _level;
        public int CurrentExp => _isProxyMode ? GetProxyExp() : _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => _isProxyMode ? GetProxyExpToNext() : GetExpRequiredForLevel(_level);
        public float ExpProgress => Level >= _maxLevel ? 1f : (float)CurrentExp / ExpToNextLevel;
        public bool IsMaxLevel => Level >= _maxLevel;

        public event System.Action<int> OnLevelChanged;
        public event System.Action<int, int> OnExpChanged;

        private bool _loadedFromSave = false;

        protected override void Awake()
        {
            base.Awake();
        }

        private void Start()
        {
            // 检测模块模式（通过场景名或全局标志判断）
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                LoadFromSave();
            }
        }

        /// <summary>
        /// 启用代理模式，将等级/经验操作转发到共享 PlayerProfile。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                _level = _profile.Level;
                _currentExp = _profile.CurrentExp;

                _profile.OnLevelChanged += OnProxyLevelChanged;
                _profile.OnExpChanged += OnProxyExpChanged;

                Debug.Log($"[PlayerLevelSystem] 代理模式已启用: Lv.{_level}");
            }
            else
            {
                LoadFromSave();
                Debug.LogWarning("[PlayerLevelSystem] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnLevelChanged -= OnProxyLevelChanged;
                _profile.OnExpChanged -= OnProxyExpChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyLevel() => _profile != null ? _profile.Level : _level;
        private int GetProxyExp() => _profile != null ? _profile.CurrentExp : _currentExp;
        private int GetProxyExpToNext() => _profile != null ? _profile.ExpToNextLevel : GetExpRequiredForLevel(_level);

        private void OnProxyLevelChanged(int level)
        {
            _level = level;
            OnLevelChanged?.Invoke(level);
        }

        private void OnProxyExpChanged(int currentExp, int expToNext)
        {
            _currentExp = currentExp;
            OnExpChanged?.Invoke(currentExp, expToNext);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = currentExp, ExpToNext = expToNext });
        }

        #endregion

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddExp(amount);
                return;
            }

            if (!_loadedFromSave)
            {
                LoadFromSave();
            }

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = _currentExp, ExpToNext = ExpToNextLevel });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                EventBus.Publish(new LevelUpEvent { NewLevel = _level, OldLevel = oldLevel });
                Debug.Log($"[PlayerLevelSystem] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        public void SetLevelData(int level, int exp)
        {
            _level = Mathf.Clamp(level, 1, _maxLevel);
            _currentExp = IsMaxLevel ? 0 : Mathf.Clamp(exp, 0, ExpToNextLevel);
            OnLevelChanged?.Invoke(_level);
            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
        }

        private void LoadFromSave()
        {
            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                var player = save.CurrentSave.player;
                SetLevelData(player.playerLevel, player.playerExp);
                _loadedFromSave = true;
                Debug.Log($"[PlayerLevelSystem] 从存档加载: Lv.{_level}, Exp={_currentExp}");
            }
            else
            {
                Debug.LogWarning("[PlayerLevelSystem] SaveSystem 未就绪，将在首次 AddExp 时重试加载");
            }
        }

        public void PersistToSave()
        {
            if (_isProxyMode)
            {
                // 代理模式下由 PlayerProfile 自己持久化
                _profile?.PersistToSave();
                return;
            }

            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                save.CurrentSave.player.playerLevel = _level;
                save.CurrentSave.player.playerExp = _currentExp;
                save.SaveGame();
            }
        }

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }

        private new void OnDestroy()
        {
            DisableProxyMode();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Core
{
    public static class EventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                (_events[eventType] as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region Event Data Structures

    public struct GameStartEvent { }
    public struct GamePauseEvent { public bool IsPaused; }
    public struct GameOverEvent { public bool IsVictory; }
    public struct WaveStartEvent { public int WaveIndex; }
    public struct WaveEndEvent { public int WaveIndex; }
    public struct EnemySpawnEvent { public GameObject Enemy; }
    public struct EnemyDeathEvent { public GameObject Enemy; public int Reward; }
    public struct EnemyReachEndEvent { public GameObject Enemy; public int Damage; }
    public struct TowerPlacedEvent { public GameObject Tower; public int Cost; }
    public struct TowerUpgradedEvent { public GameObject Tower; public int Level; }
    public struct TowerSoldEvent { public GameObject Tower; public int Refund; }
    public struct GoldChangedEvent { public int CurrentGold; public int Change; }
    public struct LifeChangedEvent { public int CurrentLife; public int Change; }
    public struct SkillUsedEvent { public string SkillName; }
    public struct ExpChangedEvent { public int Level; public int CurrentExp; public int ExpToNext; }
    public struct LevelUpEvent { public int OldLevel; public int NewLevel; }

    #endregion
}

