namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑存档数据。
    /// </summary>
    [Serializable]
    public class BuildingSaveEntry
    {
        public string buildingId;
        public float posX;
        public float posY;
        public int level;
    }

    /// <summary>
    /// 家园存档数据。
    /// </summary>
    [Serializable]
    public class HomeSaveData
    {
        public int wood;
        public int stone;
        public int food;
        public List<BuildingSaveEntry> buildings = new List<BuildingSaveEntry>();
    }

    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级和拆除。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;

        private List<BuildingBase> _buildings = new List<BuildingBase>();

        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyList<BuildingBase> Buildings => _buildings;

        #region 放置与检测

        /// <summary>
        /// 在指定世界坐标放置建筑。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector3 worldPos)
        {
            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && levelData.buildCost > 0 && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data);
            _buildings.Add(building);
            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {worldPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定建筑。
        /// </summary>
        public bool RemoveBuilding(BuildingBase building)
        {
            if (building == null || !_buildings.Contains(building))
                return false;

            _buildings.Remove(building);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置附近的建筑。
        /// </summary>
        public BuildingBase GetBuildingNear(Vector3 worldPos, float radius = 1f)
        {
            float minDist = float.MaxValue;
            BuildingBase nearest = null;
            foreach (var b in _buildings)
            {
                if (b == null) continue;
                float dist = Vector3.Distance(b.transform.position, worldPos);
                if (dist < radius && dist < minDist)
                {
                    minDist = dist;
                    nearest = b;
                }
            }
            return nearest;
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var building in _buildings)
            {
                if (building == null) continue;
                result.Add(new BuildingSaveEntry
                {
                    buildingId = building.Data.buildingId,
                    posX = building.transform.position.x,
                    posY = building.transform.position.y,
                    level = building.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                Vector3 worldPos = new Vector3(entry.posX, entry.posY, 0f);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, entry.level);
                _buildings.Add(building);
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = new GameObject($"Building_{data.buildingName}");
            go.transform.position = worldPos;
            go.transform.SetParent(transform);

            SpriteRenderer sr = go.AddComponent<SpriteRenderer>();
            sr.sprite = data.icon;
            if (sr.sprite == null)
            {
                sr.color = GetBuildingColor(data.buildingType);
            }
            sr.sortingOrder = 10;

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 传送门建筑，点击后切换到目标场景。
    /// </summary>
    public class PortalBuilding : BuildingBase
    {
        [Header("传送门特效")]
        [SerializeField] private Color _portalColor = new Color(0.3f, 0.5f, 1f, 0.8f);
        [SerializeField] private float _pulseSpeed = 2f;
        [SerializeField] private float _pulseAmount = 0.1f;

        private SpriteRenderer _renderer;
        private float _timer;
        private bool _isHovered = false;
        private Vector3 _baseScale;

        public string TargetModuleId => _data != null ? _data.targetModuleId : "";
        public string TargetSceneName => _data != null ? _data.targetSceneName : "";

        protected override void OnUpgraded()
        {
        }

        private void Start()
        {
            if (_data != null && !_isPlaced)
            {
                _isPlaced = true;
            }

            _renderer = GetComponent<SpriteRenderer>();
            _baseScale = transform.localScale;
            if (_renderer != null)
            {
                _renderer.color = _portalColor;
            }
        }

        private new void Update()
        {
            if (!_isPlaced && _data != null)
            {
                _isPlaced = true;
            }

            _timer += Time.deltaTime;

            if (_renderer != null)
            {
                float pulse = 1f + Mathf.Sin(_timer * _pulseSpeed) * _pulseAmount;
                transform.localScale = _baseScale * pulse;
            }
        }

        /// <summary>
        /// 点击传送门，切换到目标场景。
        /// </summary>
        public void OnPortalClicked()
        {
            string sceneName = TargetSceneName;
            if (string.IsNullOrEmpty(sceneName))
            {
                Debug.LogWarning("[PortalBuilding] 未配置目标场景");
                return;
            }

            Debug.Log($"[PortalBuilding] 进入传送门: {_data.buildingName} → 场景 {sceneName}");
            SceneManager.LoadScene(sceneName);
        }

        private void OnMouseDown()
        {
            if (!_isPlaced) return;
            OnPortalClicked();
        }

        private void OnMouseEnter()
        {
            _isHovered = true;
            if (_renderer != null)
                _renderer.color = new Color(_portalColor.r, _portalColor.g, _portalColor.b, 1f);
        }

        private void OnMouseExit()
        {
            _isHovered = false;
            if (_renderer != null)
                _renderer.color = _portalColor;
        }
    }
}

using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 传送门特效控制器，管理光晕脉冲和粒子强度。
    /// </summary>
    [RequireComponent(typeof(Light))]
    public class PortalEffectController : MonoBehaviour
    {
        [Header("脉冲配置")]
        [SerializeField] private float _pulseSpeed = 2f;
        [SerializeField] private float _minIntensity = 1f;
        [SerializeField] private float _maxIntensity = 3f;
        [SerializeField] private float _minRange = 1.5f;
        [SerializeField] private float _maxRange = 2.5f;

        private Light _light;
        private float _timer;

        private void Start()
        {
            _light = GetComponent<Light>();
        }

        private void Update()
        {
            if (_light == null) return;

            _timer += Time.deltaTime;
            float t = (Mathf.Sin(_timer * _pulseSpeed) + 1f) * 0.5f; // 0~1
            _light.intensity = Mathf.Lerp(_minIntensity, _maxIntensity, t);
            _light.range = Mathf.Lerp(_minRange, _maxRange, t);
        }
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源建筑，自动产出资源。
    /// </summary>
    public class ResourceBuilding : BuildingBase
    {
        private float _accumulated;

        protected override void BuildingUpdate()
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen)
                return;

            var levelData = CurrentLevelData;
            if (levelData.productionRate <= 0) return;

            _productionTimer += Time.deltaTime;
            float interval = 1f / levelData.productionRate;

            if (_productionTimer >= interval)
            {
                _productionTimer -= interval;
                _accumulated++;

                if (_accumulated >= levelData.productionCapacity)
                {
                    CollectResources();
                }
            }
        }

        /// <summary>
        /// 收集已产出的资源。
        /// </summary>
        public int CollectResources()
        {
            int collected = (int)_accumulated;
            if (collected <= 0) return 0;

            _accumulated = 0;

            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                switch (_data.producedResource)
                {
                    case ResourceType.Gold:
                        profile.AddGold(collected, "home_resource");
                        break;
                    case ResourceType.Diamond:
                        profile.AddDiamond(collected, "home_resource");
                        break;
                }
            }

            Debug.Log($"[ResourceBuilding] 收集 {collected} {_data.producedResource} from {_data.buildingName}");
            return collected;
        }

        /// <summary>
        /// 计算离线收益。
        /// </summary>
        public int CalculateOfflineEarnings(float offlineSeconds)
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen) return 0;
            var levelData = CurrentLevelData;
            return Mathf.FloorToInt(levelData.productionRate * offlineSeconds);
        }

        protected override void OnUpgraded()
        {
            // 升级后立即收集一次
            CollectResources();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源管理器，管理家园中的资源产出和收集。
    /// </summary>
    public class ResourceManager : MonoBehaviour
    {
        [Header("本地资源")]
        [SerializeField] private int _wood = 0;
        [SerializeField] private int _stone = 0;
        [SerializeField] private int _food = 0;

        public int Wood => _wood;
        public int Stone => _stone;
        public int Food => _food;

        public event Action<int, int, int> OnLocalResourcesChanged;

        #region 本地资源操作

        public void AddWood(int amount)
        {
            if (amount <= 0) return;
            _wood += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddStone(int amount)
        {
            if (amount <= 0) return;
            _stone += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddFood(int amount)
        {
            if (amount <= 0) return;
            _food += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public bool SpendWood(int amount)
        {
            if (_wood < amount) return false;
            _wood -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendStone(int amount)
        {
            if (_stone < amount) return false;
            _stone -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendFood(int amount)
        {
            if (_food < amount) return false;
            _food -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        #endregion

        #region 收集所有建筑产出

        /// <summary>
        /// 收集所有资源建筑的产出。
        /// </summary>
        public void CollectAllResources()
        {
            var buildingManager = FindObjectOfType<BuildingManager>();
            if (buildingManager == null) return;

            int totalCollected = 0;
            foreach (var building in buildingManager.Buildings)
            {
                var resourceBuilding = building as ResourceBuilding;
                if (resourceBuilding != null)
                {
                    totalCollected += resourceBuilding.CollectResources();
                }
            }

            if (totalCollected > 0)
            {
                Debug.Log($"[ResourceManager] 收集所有建筑产出: {totalCollected}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave(HomeSaveData data)
        {
            if (data == null) return;
            _wood = data.wood;
            _stone = data.stone;
            _food = data.food;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void SaveToSave(HomeSaveData data)
        {
            data.wood = _wood;
            data.stone = _stone;
            data.food = _food;
        }

        #endregion
    }
}

