        #endregion

        #region 事件

        public event Action<int> OnGoldChanged;
        public event Action<int> OnDiamondChanged;
        public event Action<int> OnStaminaChanged;
        public event Action<int> OnLevelChanged;
        public event Action<int, int> OnExpChanged;

        #endregion

        protected override void Awake()
        {
            base.Awake();
            _gold = _initialGold;
            _diamond = _initialDiamond;
            _stamina = _initialStamina;
        }

        private void Start()
        {
            LoadFromSave();
        }

        #region 金币

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount, string source = "")
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = amount,
                DiamondDelta = 0
            });
        }

        public bool SpendGold(int amount, string source = "")
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = -amount,
                DiamondDelta = 0
            });
            return true;
        }

        #endregion

        #region 钻石

        public bool HasEnoughDiamond(int amount) => _diamond >= amount;

        public void AddDiamond(int amount, string source = "")
        {
            if (amount <= 0) return;
            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = amount
            });
        }

        public bool SpendDiamond(int amount, string source = "")
        {
            if (!HasEnoughDiamond(amount)) return false;
            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            GlobalEventBus.Publish(new PlayerCurrencyChangedEvent
            {
                Source = source,
                GoldDelta = 0,
                DiamondDelta = -amount
            });
            return true;
        }

        #endregion

        #region 体力

        public bool HasEnoughStamina(int amount) => _stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;
            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (!HasEnoughStamina(amount)) return false;
            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region 等级与经验

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            GlobalEventBus.Publish(new PlayerLevelChangedEvent
            {
                OldLevel = oldLevel,
                NewLevel = _level,
                CurrentExp = _currentExp,
                ExpToNext = ExpToNextLevel
            });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                Debug.Log($"[PlayerProfile] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            var data = saveSystem.CurrentSave.player;
            _gold = data.gold > 0 ? data.gold : _initialGold;
            _diamond = data.diamond > 0 ? data.diamond : _initialDiamond;
            _stamina = data.stamina > 0 ? data.stamina : _initialStamina;
            _level = Mathf.Clamp(data.playerLevel, 1, _maxLevel);
            _currentExp = Mathf.Clamp(data.playerExp, 0, ExpToNextLevel);

            Debug.Log($"[PlayerProfile] 从存档加载: Lv.{_level}, Gold={_gold}, Diamond={_diamond}");
        }

        public void PersistToSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null || saveSystem.CurrentSave == null) return;

            saveSystem.CurrentSave.player.gold = _gold;
            saveSystem.CurrentSave.player.diamond = _diamond;
            saveSystem.CurrentSave.player.stamina = _stamina;
            saveSystem.CurrentSave.player.playerLevel = _level;
            saveSystem.CurrentSave.player.playerExp = _currentExp;
            saveSystem.SaveGame();
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Shared.Save
{
    /// <summary>
    /// 存档数据结构，支持模块化存档。
    /// 每个游戏模块将自己的数据序列化为 JSON 字符串存入 moduleData 字典。
    /// </summary>
    [Serializable]
    public class GameSaveData
    {
        public int version = 1;
        public PlayerSaveData player = new PlayerSaveData();
        public SettingsSaveData settings = new SettingsSaveData();
        public string lastActiveModuleId = "home";

        /// <summary>模块存档数据列表</summary>
        public List<ModuleSaveEntry> moduleData = new List<ModuleSaveEntry>();

        [Serializable]
        public class PlayerSaveData
        {
            public int gold;
            public int diamond;
            public int stamina;
            public int playerLevel = 1;
            public int playerExp;
            public int totalGamesPlayed;
            public float totalPlayTime;
            public long lastLoginTimeTicks;
        }

        [Serializable]
        public class SettingsSaveData
        {
            public float musicVolume = 1f;
            public float sfxVolume = 1f;
            public bool isFullscreen = true;
            public int qualityLevel = 2;
            public string language = "zh";
        }

        [Serializable]
        public class ModuleSaveEntry
        {
            public string moduleId;
            public string dataJson;
            public int dataVersion;
        }
    }

    /// <summary>
    /// 模块存档接口，每个游戏模块实现此接口以提供存档支持。
    /// </summary>
    public interface IModuleSaveData
    {
        string ModuleId { get; }
        int DataVersion { get; }
        string Serialize();
        void Deserialize(string json);
    }
}

using System;
using System.IO;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Shared.Save
{
    /// <summary>
    /// 统一存档系统，管理跨所有模块的存档数据。
    /// 支持模块化存档：每个游戏模块独立管理自己的存档数据。
    /// </summary>
    public class SaveSystem : Core.Singleton<SaveSystem>
    {
        private const string SAVE_FILE = "gamesave.json";
        private const string SAVE_FOLDER = "Save";
        private const int CURRENT_VERSION = 1;

        private GameSaveData _currentSave;
        private string SavePath => Path.Combine(Application.persistentDataPath, SAVE_FOLDER, SAVE_FILE);

        public GameSaveData CurrentSave => _currentSave;

        protected override void Awake()
        {
            base.Awake();
            LoadGame();
        }

        #region 基础存档操作

        /// <summary>
        /// 保存游戏到磁盘。
        /// </summary>
        public void SaveGame()
        {
            try
            {
                string directory = Path.GetDirectoryName(SavePath);
                if (!Directory.Exists(directory))
                {
                    Directory.CreateDirectory(directory);
                }

                _currentSave.version = CURRENT_VERSION;
                _currentSave.player.lastLoginTimeTicks = DateTime.Now.Ticks;

                string json = JsonUtility.ToJson(_currentSave, true);
                File.WriteAllText(SavePath, json);

                Debug.Log("[SaveSystem] 游戏已保存");
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 保存失败: {e.Message}");
            }
        }

        /// <summary>
        /// 从磁盘加载游戏。
        /// </summary>
        public void LoadGame()
        {
            try
            {
                if (File.Exists(SavePath))
                {
                    string json = File.ReadAllText(SavePath);
                    _currentSave = JsonUtility.FromJson<GameSaveData>(json);
                    Debug.Log("[SaveSystem] 存档已加载");
                }
                else
                {
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] 无存档文件，创建新存档");
                }
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 加载失败: {e.Message}");
                _currentSave = new GameSaveData();
            }
        }

        /// <summary>
        /// 删除存档文件。
        /// </summary>
        public void DeleteSave()
        {
            try
            {
                if (File.Exists(SavePath))
                {
                    File.Delete(SavePath);
                }
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] 存档已删除");
            }
            catch (Exception e)
            {
                Debug.LogError($"[SaveSystem] 删除存档失败: {e.Message}");
            }
        }

        #endregion

        #region 模块化存档

        /// <summary>
        /// 保存指定模块的存档数据。
        /// </summary>
        public void SaveModuleData(string moduleId, string jsonData, int dataVersion)
        {
            if (string.IsNullOrEmpty(moduleId)) return;

            var entry = _currentSave.moduleData.Find(m => m.moduleId == moduleId);
            if (entry == null)
            {
                entry = new GameSaveData.ModuleSaveEntry
                {
                    moduleId = moduleId
                };
                _currentSave.moduleData.Add(entry);
            }

            entry.dataJson = jsonData;
            entry.dataVersion = dataVersion;
            SaveGame();
        }

        /// <summary>
        /// 保存模块存档数据（通过 IModuleSaveData 接口）。
        /// </summary>
        public void SaveModuleData(IModuleSaveData moduleData)
        {
            SaveModuleData(moduleData.ModuleId, moduleData.Serialize(), moduleData.DataVersion);
        }

        /// <summary>
        /// 加载指定模块的存档数据。
        /// </summary>
        public string LoadModuleData(string moduleId)
        {
            var entry = _currentSave.moduleData.Find(m => m.moduleId == moduleId);
            return entry?.dataJson;
        }

        /// <summary>
        /// 加载模块存档数据并反序列化。
        /// </summary>
        public T LoadModuleData<T>() where T : IModuleSaveData, new()
        {
            var data = new T();
            var json = LoadModuleData(data.ModuleId);
            if (!string.IsNullOrEmpty(json))
            {
                try
                {
                    data.Deserialize(json);
                }
                catch (Exception e)
                {
                    Debug.LogError($"[SaveSystem] 模块存档反序列化失败: {data.ModuleId} - {e.Message}");
                }
            }
            return data;
        }

        /// <summary>
        /// 删除指定模块的存档数据。
        /// </summary>
        public void DeleteModuleData(string moduleId)
        {
            _currentSave.moduleData.RemoveAll(m => m.moduleId == moduleId);
            SaveGame();
        }

        /// <summary>
        /// 保存所有已注册模块的存档数据。
        /// </summary>
        public void SaveAllModules()
        {
            var moduleManager = Core.ModuleManager.Instance;
            if (moduleManager == null) return;

            var allData = moduleManager.CollectAllModuleSaveData();
            foreach (var kvp in allData)
            {
                var entry = _currentSave.moduleData.Find(m => m.moduleId == kvp.Key);
                if (entry == null)
                {
                    entry = new GameSaveData.ModuleSaveEntry { moduleId = kvp.Key };
                    _currentSave.moduleData.Add(entry);
                }
                entry.dataJson = kvp.Value;
            }

            SaveGame();
        }

        #endregion

        #region 设置

        public void SaveSettings(float musicVolume, float sfxVolume, bool fullscreen, int quality)
        {
            _currentSave.settings.musicVolume = musicVolume;
            _currentSave.settings.sfxVolume = sfxVolume;
            _currentSave.settings.isFullscreen = fullscreen;
            _currentSave.settings.qualityLevel = quality;
            SaveGame();
        }

        public void LoadSettings()
        {
            AudioListener.volume = _currentSave.settings.sfxVolume;
            Screen.fullScreen = _currentSave.settings.isFullscreen;
            QualitySettings.SetQualityLevel(_currentSave.settings.qualityLevel);
        }

        #endregion

        #region 自动保存

        private float _autoSaveInterval = 60f;
        private float _autoSaveTimer;

        private void Update()
        {
            _autoSaveTimer += Time.unscaledDeltaTime;
            if (_autoSaveTimer >= _autoSaveInterval)
            {
                _autoSaveTimer = 0f;
                SaveGame();
            }
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveGame();
        }

        private void OnApplicationQuit()
        {
            SaveGame();
        }
    }
}

using UnityEngine;
using TowerDefense.Tower;
using TowerDefense.Data;

public class TowerPlacementTest : MonoBehaviour
{
    [SerializeField] private TowerData towerData;

    /// <summary>
    /// 当前选中的槽位
    /// </summary>
    private TowerSlot _selectedSlot;

    private void Update()
    {
        // 检测鼠标点击槽位
        if (Input.GetMouseButtonDown(0))
        {
            Ray ray = Camera.main.ScreenPointToRay(Input.mousePosition);
            RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction);

            if (hit.collider != null)
            {
                TowerSlot slot = hit.collider.GetComponent<TowerSlot>();
                if (slot != null)
                {
                    // 取消之前选中的槽位高亮
                    if (_selectedSlot != null)
                    {
                        _selectedSlot.DeselectSlot();
                    }

                    // 选中新槽位
                    _selectedSlot = slot;
                    _selectedSlot.SelectSlot();

                    Debug.Log($"Selected slot: {_selectedSlot.name}");
                }
            }
        }
    }

    /// <summary>
    /// 放置塔按钮回调
    /// </summary>
    public void OnPlaceTowerButton()
    {
        if (towerData == null)
        {
            Debug.LogError("Tower Data is not assigned!");
            return;
        }

        // 如果没有选中槽位，提示玩家
        if (_selectedSlot == null)
        {
            Debug.LogWarning("⚠️ Please click on a tower slot first!");
            return;
        }

        // 在选中的槽位放置塔
        bool success = _selectedSlot.PlaceTower(towerData);

        if (success)
        {
            Debug.Log($"✅ Tower placed successfully on slot: {_selectedSlot.name}");

            // 取消选中状态
            _selectedSlot.DeselectSlot();
            _selectedSlot = null;
        }
        else
        {
            Debug.LogWarning("❌ Failed to place tower! Check gold or slot status.");
        }
    }

    /// <summary>
    /// 获取当前选中的槽位
    /// </summary>
    public TowerSlot GetSelectedSlot()
    {
        return _selectedSlot;
    }
}

using UnityEngine;
using UnityEngine.Events;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.UI;

namespace TowerDefense.Tower
{
    /// <summary>
    /// 塔槽位组件 - 管理塔的放置、移除、升级和售卖
    /// </summary>
    public class TowerSlot : MonoBehaviour
    {
        [Header("Slot Settings")]
        [Tooltip("是否已被占用")]
        [SerializeField] private bool _isOccupied = false;

        [Tooltip("当前塔实例")]
        [SerializeField] private Tower _currentTower;

        [Tooltip("高亮效果物体")]
        [SerializeField] private GameObject _highlight;

        [Tooltip("建造指示器")]
        [SerializeField] private GameObject _buildIndicator;

        [Header("Slot Type")]
        [Tooltip("槽位类型")]
        [SerializeField] private LevelData.SlotType _slotType = LevelData.SlotType.Normal;

        [Header("Spawn Settings")]
        [Tooltip("塔的Z轴位置")]
        [SerializeField] private float _towerZPosition = -1f;

        [Tooltip("塔的缩放")]
        [SerializeField] private Vector3 _towerScale = Vector3.one;

        [Header("Build Button Settings")]
        [Tooltip("可以建造的塔列表")]
        [SerializeField] private TowerData[] buildableTowers;

        [Header("Events")]
        [Tooltip("塔放置事件")]
        public UnityEvent OnTowerPlaced;

        [Tooltip("塔移除事件")]
        [SerializeField] private UnityEvent OnTowerRemoved;

        [Tooltip("槽位选中事件")]
        public UnityEvent OnSlotSelected;

        /// <summary>
        /// 是否已被占用
        /// </summary>
        public bool IsOccupied => _isOccupied;

        /// <summary>
        /// 当前塔实例
        /// </summary>
        public Tower CurrentTower => _currentTower;

        /// <summary>
        /// 槽位类型
        /// </summary>
        public LevelData.SlotType SlotType => _slotType;

        /// <summary>
        /// 是否处于悬停状态
        /// </summary>
        private bool _isHovered = false;

        /// <summary>
        /// 是否处于选中状态
        /// </summary>
        private bool _isSelected = false;

        /// <summary>
        /// 初始化组件
        /// </summary>
        private void Awake()
        {
           // Debug.Log($"TowerSlot {gameObject.name} initialized");

            // 初始化高亮和建造指示器状态
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(!_isOccupied);
            }
        }

        /// <summary>
        /// 鼠标进入槽位
        /// </summary>
        private void OnMouseEnter()
        {
            if (!_isOccupied)
            {
                _isHovered = true;
                // Debug.Log($"Mouse entered slot: {gameObject.name}");

                // 显示高亮效果
                if (_highlight != null)
                {
                    _highlight.SetActive(true);
                }
            }
        }

        /// <summary>
        /// 鼠标离开槽位
        /// </summary>
        private void OnMouseExit()
        {
            _isHovered = false;
            // 非选中状态下隐藏高亮
            if (_highlight != null && !_isSelected)
            {
                _highlight.SetActive(false);
            }
        }

        void Start()
        {
            CircleCollider2D collider = GetComponent<CircleCollider2D>();
            if (collider != null)
            {
                collider.radius = 1f;
            }
        }

        /// <summary>
        /// 鼠标点击槽位
        /// </summary>
        private void OnMouseDown()
        {
            Debug.Log($"Slot clicked: {gameObject.name}, IsOccupied: {_isOccupied}");

            // 取消之前的选中状态（不隐藏面板，面板常驻）
            DeselectAllSlots();
            HideTowerInfoPanel();

            if (!_isOccupied)
            {
                SelectSlot();
                ShowTowerSelectPanel();
            }
            else
            {
                SelectSlot();
                ShowTowerInfoPanel();
            }
        }

        /// <summary>
        /// 选中槽位
        /// </summary>
        public void SelectSlot()
        {
            _isSelected = true;
            OnSlotSelected?.Invoke();
                // Debug.Log($"Slot selected: {gameObject.name}");

            // 如果有塔，显示攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.ShowRange();
            }
        }

        /// <summary>
        /// 取消选中槽位
        /// </summary>
        public void DeselectSlot()
        {
            _isSelected = false;
            // 隐藏高亮效果
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 如果有塔，隐藏攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.HideRange();
            }
                // Debug.Log($"Slot deselected: {gameObject.name}");
        }

        /// <summary>
        /// 显示塔选择面板
        /// </summary>
        private void ShowTowerSelectPanel()
        {
            // 先尝试通过 画布 下已知路径查找（包括非激活对象）
            TowerSelectPanel panel = null;
            var panelObj = GameObject.Find("画布/塔选择面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：用英文名查找（兼容重命名前）
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerSelectPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：在激活对象中查找
            if (panel == null)
            {
                panel = FindObjectOfType<TowerSelectPanel>();
            }

            if (panel != null)
            {
                panel.Show(this);
            }
        }

        /// <summary>
        /// 显示塔信息面板
        /// </summary>
        private void ShowTowerInfoPanel()
        {
            TowerInfoPanel panel = null;
            var panelObj = GameObject.Find("画布/塔信息面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerInfoPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panel = FindObjectOfType<TowerInfoPanel>();
            }
            if (panel != null && _currentTower != null)
            {
                panel.Show(_currentTower);
            }
        }

        /// <summary>
        /// 取消所有槽位的选中状态
        /// </summary>
        private void DeselectAllSlots()
        {
            foreach (var slot in FindObjectsOfType<TowerSlot>())
            {
                if (slot._isSelected)
                {
                    slot.DeselectSlot();
                }
            }
        }

        /// <summary>
        /// 隐藏塔信息面板
        /// </summary>
        private void HideTowerInfoPanel()
        {
            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }
        }

        /// <summary>
        /// 隐藏所有UI面板
        /// </summary>
        private void HideAllPanels()
        {
            var selectObj = GameObject.Find("画布/塔选择面板");
            if (selectObj == null) selectObj = GameObject.Find("Canvas/TowerSelectPanel");
            if (selectObj != null)
            {
                var selectPanel = selectObj.GetComponent<TowerSelectPanel>();
                if (selectPanel != null) selectPanel.Hide();
            }
            else
            {
                var sp = FindObjectOfType<TowerSelectPanel>();
                if (sp != null) sp.Hide();
            }

            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

