            TowerData towerToBuild = GetTowerDataToBuild();

            if (towerToBuild != null)
            {
                bool success = PlaceTower(towerToBuild);

                if (success)
                {
                    // Debug.Log("✅ Tower built successfully!");
                }
                else
                {
                    // Debug.Log("❌ Failed to build tower!");
                }
            }
            else
            {
                // Debug.LogError("❌ No tower data to build!");
            }
        }

        /// <summary>
        /// 获取要建造的塔数据
        /// </summary>
        private TowerData GetTowerDataToBuild()
        {
            // 优先使用配置的塔列表
            if (buildableTowers != null && buildableTowers.Length > 0)
            {
                    // Debug.Log($"Using configured tower: {buildableTowers[0].towerName}");
                return buildableTowers[0];
            }

            // 尝试从Resources/Data/Towers/加载
            Debug.Log("Trying to load from Resources/Data/Towers/");
            TowerData[] towerDatas1 = Resources.LoadAll<TowerData>("Data/Towers");
            if (towerDatas1.Length > 0)
            {
                     Debug.Log($"Found {towerDatas1.Length} tower data assets in Data/Towers/");
                return towerDatas1[0];
            }

            // 尝试从Resources/Data/加载
            Debug.Log("Trying to load from Resources/Data/");
            TowerData[] towerDatas2 = Resources.LoadAll<TowerData>("Data");
            if (towerDatas2.Length > 0)
            {
                Debug.Log($"Found {towerDatas2.Length} tower data assets in Data/");
                return towerDatas2[0];
            }

                Debug.LogError("❌ No tower data found!");
            return null;
        }

        /// <summary>
        /// 在槽位放置塔
        /// </summary>
        /// <param name="towerData">塔数据</param>
        /// <returns>是否放置成功</returns>
        public bool PlaceTower(TowerData towerData)
        {
            if (_isOccupied) return false;

            int cost = towerData.levels[0].cost;
            if (!GameManager.Instance.SpendGold(cost)) return false;

            Vector3 spawnPos = transform.position;
            spawnPos.z = _towerZPosition;

            GameObject towerObj = Instantiate(towerData.towerPrefab, spawnPos, Quaternion.identity);
            if (towerObj == null) return false;

            if (_towerScale != Vector3.one)
            {
                towerObj.transform.localScale = _towerScale;
            }

            _currentTower = towerObj.GetComponent<Tower>();
            if (_currentTower != null)
            {
                _currentTower.Initialize(towerData, this);
            }

            _isOccupied = true;

            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(false);
            }
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            OnTowerPlaced?.Invoke();
            EventBus.Publish(new TowerPlacedEvent { Tower = towerObj, Cost = cost });

            return true;
        }

        /// <summary>
        /// 移除塔（不返还金币）
        /// </summary>
        public void RemoveTower()
        {
            _currentTower = null;
            _isOccupied = false;

            // 显示建造指示器
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(true);
            }

            OnTowerRemoved?.Invoke();
        }

        /// <summary>
        /// 售卖塔（返还部分金币）
        /// </summary>
        public void SellTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Sell();
        }

        /// <summary>
        /// 升级塔
        /// </summary>
        public void UpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Upgrade();
        }

        /// <summary>
        /// 获取塔的售卖价值
        /// </summary>
        /// <returns>售卖金币数</returns>
        public int GetTowerSellValue()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetSellValue();
        }

        /// <summary>
        /// 获取塔的升级费用
        /// </summary>
        /// <returns>升级金币数</returns>
        public int GetTowerUpgradeCost()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetUpgradeCost();
        }

        /// <summary>
        /// 检查塔是否可以升级
        /// </summary>
        /// <returns>是否可升级</returns>
        public bool CanUpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return false;
            return !_currentTower.IsMaxLevel;
        }

        /// <summary>
        /// 绘制Gizmos（编辑器模式下）
        /// </summary>
        private void OnDrawGizmos()
        {
            // 绿色表示可建造，红色表示已占用
            Gizmos.color = _isOccupied ? Color.red : Color.green;
            Gizmos.DrawWireSphere(transform.position, 0.3f);
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public enum TowerState
    {
        Idle,
        Targeting,
        Attacking,
        Upgrading,
        Selling
    }

    public class Tower : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] protected TowerData _towerData;
        [SerializeField] protected TowerAttack _attack;
        [SerializeField] protected Animator _animator;
        [SerializeField] protected Transform _rotatePart;
        [SerializeField] protected SpriteRenderer _spriteRenderer;

        [Header("Visual")]
        [SerializeField] protected GameObject _rangeIndicator;
        [SerializeField] protected Color _rangeColor = new Color(0, 1, 0, 0.3f);
        [Tooltip("Rotation offset in degrees. Default -90 assumes sprite faces UP. Change to 0 if sprite faces RIGHT.")]
        [SerializeField] protected float _rotationOffset = -90f;

        protected int _currentLevel = 1;
        protected TowerState _currentState = TowerState.Idle;
        protected TowerData.TowerStats _currentStats;
        protected Enemy.Enemy _currentTarget;
        protected TowerSlot _slot;

        public TowerData Data => _towerData;
        public int CurrentLevel => _currentLevel;
        public TowerState State => _currentState;
        public Enemy.Enemy CurrentTarget => _currentTarget;
        public TowerData.TowerStats CurrentStats => _currentStats;
        public TowerSlot Slot => _slot;
        public bool IsMaxLevel => _currentLevel >= _towerData.levels.Length;

        public System.Action<Tower> OnUpgrade;
        public System.Action<Tower> OnSell;
        public System.Action<Enemy.Enemy> OnTargetAcquired;
        public System.Action OnTargetLost;

        protected virtual void Awake()
        {
            if (_attack == null) _attack = GetComponent<TowerAttack>();
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
        }

        public virtual void Initialize(TowerData data, TowerSlot slot)
        {
            _towerData = data;
            _slot = slot;
            _currentLevel = 1;
            _currentStats = data.levels[0];
            _currentState = TowerState.Idle;

            if (_attack != null)
            {
                _attack.Initialize(this);
            }

            UpdateRangeIndicator();
        }

        protected virtual void Update()
        {
            if (_currentState == TowerState.Upgrading || _currentState == TowerState.Selling)
                return;

            FindTarget();

            if (_currentTarget != null)
            {
                RotateTowardsTarget();
                Attack();
            }
        }

        protected virtual void FindTarget()
        {
            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;

            if (_currentTarget != null && !_currentTarget.IsDead)
            {
                float distance = Vector3.Distance(transform.position, _currentTarget.transform.position);
                if (distance <= actualAttackRange)
                {
                    return;
                }
            }

            _currentTarget = FindBestTarget();

            if (_currentTarget != null)
            {
                _currentState = TowerState.Targeting;
                OnTargetAcquired?.Invoke(_currentTarget);
            }
            else
            {
                _currentState = TowerState.Idle;
                OnTargetLost?.Invoke();
            }
        }

        protected virtual Enemy.Enemy FindBestTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null)
            {
                Debug.LogError("EnemySpawner not found!");
                return null;
            }

            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;
            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, actualAttackRange);

            if (enemiesInRange.Count == 0) return null;

            Enemy.Enemy bestTarget = null;
            float bestPriority = float.MinValue;

            foreach (var enemy in enemiesInRange)
            {
                if (enemy == null || enemy.IsDead) continue;

                float priority = CalculateTargetPriority(enemy);
                if (priority > bestPriority)
                {
                    bestPriority = priority;
                    bestTarget = enemy;
                }
            }

            return bestTarget;
        }

        protected virtual float CalculateTargetPriority(Enemy.Enemy enemy)
        {
            EnemyMovement movement = enemy.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                return movement.GetProgressPercent();
            }
            return 0f;
        }

        protected virtual void RotateTowardsTarget()
        {
            if (_currentTarget == null) return;
            if (_towerData != null && (_towerData.towerType == TowerType.Barracks || _towerData.towerType == TowerType.Mage)) return;

            Transform rotateTransform = GetRotateTransform();
            if (rotateTransform == null) return;

            Vector3 direction = _currentTarget.transform.position - rotateTransform.position;
            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg + _rotationOffset;
            Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
            rotateTransform.rotation = Quaternion.Slerp(rotateTransform.rotation, targetRotation, 10f * Time.deltaTime);
        }

        /// <summary>
        /// Returns the transform that should rotate towards the target.
        /// Uses _rotatePart if it has a visual (renderer in children), 
        /// otherwise falls back to the sprite renderer's transform.
        /// </summary>
        protected Transform GetRotateTransform()
        {
            if (_rotatePart != null)
            {
                if (_rotatePart.GetComponent<Renderer>() != null || _rotatePart.GetComponentInChildren<Renderer>() != null)
                    return _rotatePart;
            }

            if (_spriteRenderer != null)
                return _spriteRenderer.transform;

            var sr = GetComponent<SpriteRenderer>();
            if (sr != null)
                return sr.transform;

            return _rotatePart;
        }

        protected virtual void Attack()
        {
            if (_attack == null) return;

            if (_attack.CanAttack())
            {
                _currentState = TowerState.Attacking;
                _attack.Attack(_currentTarget);
            }
        }

        public virtual bool Upgrade()
        {
            if (IsMaxLevel) return false;

            TowerData.TowerStats nextLevelStats = _towerData.levels[_currentLevel];
            if (!GameManager.Instance.SpendGold(nextLevelStats.upgradeCost)) return false;

            _currentLevel++;
            _currentStats = nextLevelStats;

            if (_animator != null)
            {
                _animator.SetTrigger("Upgrade");
            }

            UpdateRangeIndicator();
            OnUpgrade?.Invoke(this);
            EventBus.Publish(new TowerUpgradedEvent { Tower = gameObject, Level = _currentLevel });

            return true;
        }

        public virtual void Sell()
        {
            Debug.Log($"📤 Tower.Sell() called for {gameObject.name}");
            Debug.Log($"   sellValue: {_currentStats.sellValue}");
            Debug.Log($"   _slot: {_slot != null}");

            int sellValue = _currentStats.sellValue;
            GameManager.Instance.AddGold(sellValue);
            Debug.Log($"   ✅ Added {sellValue} gold");

            OnSell?.Invoke(this);
            EventBus.Publish(new TowerSoldEvent { Tower = gameObject, Refund = sellValue });

            if (_slot != null)
            {
                _slot.RemoveTower();
                Debug.Log($"   ✅ Called _slot.RemoveTower()");
            }

            Destroy(gameObject);
            Debug.Log($"   ✅ Tower destroyed");
        }

        public int GetUpgradeCost()
        {
            if (IsMaxLevel) return 0;
            return _towerData.levels[_currentLevel].upgradeCost;
        }

        public int GetSellValue()
        {
            return _currentStats.sellValue;
        }

        public void ShowRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(true);
            }
        }

        public void HideRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(false);
            }
        }

        protected void UpdateRangeIndicator()
        {
            if (_rangeIndicator != null)
            {
                float scale = _currentStats.attackRange * 2f;
                _rangeIndicator.transform.localScale = new Vector3(scale, scale, 1f);
            }
        }

        private void OnDrawGizmosSelected()
        {
            if (_towerData != null && _currentStats.attackRange > 0)
            {
                Gizmos.color = _rangeColor;
                Gizmos.DrawWireSphere(transform.position, _currentStats.attackRange);
            }
        }
    }
}

using System.Collections;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class TowerAttack : MonoBehaviour
    {
        [Header("Attack Settings")]
        [SerializeField] private Transform _firePoint;
        [SerializeField] private bool _autoFire = true;

        protected Transform FirePoint => _firePoint;

        protected Tower _tower;
        protected float _attackCooldown = 0f;
        protected bool _canAttack = true;

        public bool CanAttackValue => _canAttack && _attackCooldown <= 0f;

        public virtual void Initialize(Tower tower)
        {
            _tower = tower;
            _attackCooldown = 0f;
        }

        protected virtual void Update()
        {
            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        public virtual bool CanAttack()
        {
            return _attackCooldown <= 0f && _tower.CurrentTarget != null;
        }

        /// <summary>
        /// Returns the effective attack range for targeting purposes.
        /// Projectile towers use their stats range; barracks use soldier engage range.
        /// </summary>
        public virtual float GetEffectiveAttackRange()
        {
            return _tower != null ? _tower.CurrentStats.attackRange : 0f;
        }

        public virtual void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            switch (_tower.Data.towerType)
            {
                case TowerType.Archer:
                    FireProjectile(target);
                    break;
                case TowerType.Mage:
                    FireMagicAttack(target);
                    break;
                case TowerType.Barracks:
                    SpawnSoldiers(target);
                    break;
                case TowerType.Artillery:
                    FireExplosive(target);
                    break;
                case TowerType.Sword:
                    FirePierceProjectile(target);
                    break;
            }

            // Barracks don't use cooldown - soldiers continuously auto-assign
            if (_tower.Data.towerType != TowerType.Barracks)
            {
                _attackCooldown = 1f / stats.attackSpeed;
            }

            if (_tower.GetComponent<Animator>() != null)
            {
                _tower.GetComponent<Animator>().SetTrigger("Attack");
            }
        }

        protected virtual void FireProjectile(Enemy.Enemy target)
        {
            Debug.Log($"FireProjectile called");
            Debug.Log($"Projectile prefab: " + _tower.Data.projectilePrefab);
            Debug.Log($"FirePoint: " + _firePoint);

            if (_tower.Data.projectilePrefab == null || _firePoint == null)
            {
                if (_tower.Data.projectilePrefab == null)
                {
                    Debug.LogError("Projectile prefab is null!");
                }
                return;
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Physical);
            }
        }

        protected virtual void FireMagicAttack(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Magic);
            }
        }

        protected virtual void FireExplosive(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(
                    target,
                    _tower.CurrentStats.damage,
                    DamageType.Explosion,
                    _tower.CurrentStats.splashRadius,
                    0,
                    _tower.CurrentStats.maxTargets
                );
            }
        }

        protected virtual void SpawnSoldiers(Enemy.Enemy target)
        {
        }

        protected virtual void FirePierceProjectile(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            int pierceCount = stats.pierceCount;
            if (pierceCount <= 0)
            {
                int towerLevel = _tower.CurrentLevel;
                pierceCount = towerLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, stats.damage, DamageType.Physical, 0f, pierceCount);
            }
        }

        public void SetFirePoint(Transform firePoint)
        {
            _firePoint = firePoint;
        }
    }
}

using UnityEngine;
using TowerDefense.Tower;

public class BuildButtonManager : MonoBehaviour
{
    public static BuildButtonManager Instance { get; private set; }

    [Tooltip("建造按钮预制体")]
    public GameObject buildButtonPrefab;

    [Tooltip("Canvas引用")]
    public Canvas uiCanvas;

    [Tooltip("按钮偏移")]
    public Vector2 buttonOffset = new Vector2(0, 50);

    private GameObject _currentButton;
    private TowerSlot _currentSlot;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        if (uiCanvas == null)
        {
            uiCanvas = FindObjectOfType<Canvas>();
        }
    }

    /// <summary>
    /// 显示建造按钮
    /// </summary>
    public void ShowBuildButton(TowerSlot slot)
    {
        // 如果有其他按钮，先隐藏
        HideBuildButton();

        if (buildButtonPrefab == null || uiCanvas == null)
        {
            Debug.LogError("BuildButtonManager: Missing prefab or Canvas!");
            return;
        }

        // 计算按钮位置
        Vector3 worldPos = Camera.main.WorldToScreenPoint(slot.transform.position);
        worldPos += new Vector3(buttonOffset.x, buttonOffset.y, 0);

        // 实例化按钮
        _currentButton = Instantiate(buildButtonPrefab);
        _currentButton.transform.SetParent(uiCanvas.transform, false);
        _currentButton.transform.position = worldPos;

        // 绑定事件
        UnityEngine.UI.Button button = _currentButton.GetComponent<UnityEngine.UI.Button>();
        if (button != null)
        {
            button.onClick.AddListener(() => OnBuildButtonClicked(slot));
        }

        _currentSlot = slot;
        Debug.Log($"Build button shown for slot: {slot.name}");
    }

    /// <summary>
    /// 隐藏建造按钮
    /// </summary>
    public void HideBuildButton()
    {
        if (_currentButton != null)
        {
            Destroy(_currentButton);
            _currentButton = null;
        }
        _currentSlot = null;
    }

    /// <summary>
    /// 建造按钮点击
    /// </summary>
    private void OnBuildButtonClicked(TowerSlot slot)
    {
        Debug.Log("Build button clicked!");

        // 先隐藏按钮
        HideBuildButton();

        // 让槽位自己处理建造逻辑
        // 这里我们直接调用一个方法
        slot.OnBuildButtonClickedByManager();
    }

    /// <summary>
    /// 检查当前是否显示了按钮
    /// </summary>
    public bool IsButtonShowing()
    {
        return _currentButton != null;
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Tower;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerSelectPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;
        [SerializeField] private Text _slotInfoText;

        [Header("Text Settings")]
        [SerializeField] private Font _buttonFont;


        [Header("Tower Data")]
        [SerializeField] private TowerData[] _availableTowers;

        private TowerSlot _currentSlot;
        private TowerData[] _towerDatas;

        private void Awake()
        {
            Debug.Log($"TowerSelectPanel Awake - _panel: {_panel != null}, _container: {_towerButtonContainer != null}, _prefab: {_towerButtonPrefab != null}, _text: {_slotInfoText != null}");

            if (_panel != null)
            {
                _panel.SetActive(true);
            }

            LoadTowerData();
            RefreshTowerButtons();
        }

        private void LoadTowerData()
        {
            if (_availableTowers != null && _availableTowers.Length > 0)
            {
                _towerDatas = _availableTowers;
            }
            else
            {
                _towerDatas = Resources.LoadAll<TowerData>("Data/Towers");

                if (_towerDatas.Length == 0)
                {
                    _towerDatas = Resources.LoadAll<TowerData>("Data");
                }
            }
        }

        public void Show(TowerSlot slot)
        {
            _currentSlot = slot;

            if (_panel == null)
            {
                Debug.LogWarning("⚠️ TowerSelectPanel 的 _panel 字段未设置！");
                return;
            }

            RefreshTowerButtons();
            _panel.SetActive(true);
        }

        public void Hide()
        {
            _currentSlot = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void RefreshTowerButtons()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                Destroy(child.gameObject);
            }

            foreach (var towerData in _towerDatas)
            {
                CreateTowerButton(towerData);
            }
        }

        private void CreateTowerButton(TowerData towerData)
        {
            GameObject buttonObj;

            if (_towerButtonPrefab == null)
            {
                buttonObj = new GameObject($"TowerButton_{towerData.towerName}");
                buttonObj.transform.SetParent(_towerButtonContainer, false);

                Button button = buttonObj.AddComponent<Button>();
                Image bgImage = buttonObj.AddComponent<Image>();
                bgImage.color = new Color(0.4f, 0.4f, 0.6f);

                RectTransform buttonRect = buttonObj.GetComponent<RectTransform>();
                buttonRect.sizeDelta = new Vector2(70, 85);

                if (towerData.icon != null)
                {
                    GameObject iconObj = new GameObject("Icon");
                    iconObj.transform.SetParent(buttonObj.transform, false);

                    Image iconImage = iconObj.AddComponent<Image>();
                    iconImage.sprite = towerData.icon;
                    iconImage.preserveAspect = true;

                    RectTransform iconRect = iconObj.GetComponent<RectTransform>();
                    iconRect.anchorMin = new Vector2(0.5f, 0.4f);
                    iconRect.anchorMax = new Vector2(0.5f, 1f);
                    iconRect.offsetMin = new Vector2(-30, 0);
                    iconRect.offsetMax = new Vector2(30, 0);
                }

                GameObject textObj = new GameObject("Text");
                textObj.transform.SetParent(buttonObj.transform, false);

                Outline outline = textObj.AddComponent<Outline>();
                outline.effectColor = Color.black;
                outline.effectDistance = new Vector2(2, -2);

                Text text = textObj.AddComponent<Text>();
                text.text = $"{GetTowerPrice(towerData)}";

                if (_buttonFont != null)
                {
                    text.font = _buttonFont;
                }

                text.fontSize = 26;
                text.fontStyle = FontStyle.Bold;
                text.alignment = TextAnchor.LowerCenter;
                text.color = new Color(1f, 0.9f, 0f);
                text.horizontalOverflow = HorizontalWrapMode.Overflow;
                text.verticalOverflow = VerticalWrapMode.Overflow;

                RectTransform textRect = textObj.GetComponent<RectTransform>();
                textRect.anchorMin = Vector2.zero;
                textRect.anchorMax = new Vector2(1f, 0.35f);
                textRect.offsetMin = Vector2.zero;
                textRect.offsetMax = Vector2.zero;

                bool canAfford = GameManager.Instance.HasEnoughGold(GetTowerPrice(towerData));
            button.interactable = canAfford;
            Debug.Log($"🔘 [动态按钮] 添加点击监听器: {towerData.towerName}");
            button.onClick.AddListener(() => {
                Debug.Log($"🖱️ [动态按钮] Lambda被调用！");
                OnTowerSelected(towerData);
            });
            Debug.Log($"🔘 [动态按钮] 点击监听器已添加！");

            if (!canAfford)
                {
                    bgImage.color = new Color(0.3f, 0.3f, 0.3f);
                }
            }
            else
            {
                buttonObj = Instantiate(_towerButtonPrefab, _towerButtonContainer);
                buttonObj.name = $"TowerButton_{towerData.towerName}";

                TowerButton towerButton = buttonObj.GetComponent<TowerButton>();
                if (towerButton != null)
                {
                    towerButton.Initialize(towerData, this);
                    Debug.Log($"📌 TowerButton 组件已初始化: {towerData.towerName}");
                }
                else
                {
                    Debug.LogWarning($"⚠️ TowerButton 预制体没有 TowerButton 组件，使用手动设置");
                    SetupButtonManually(buttonObj, towerData);
                }
            }
        }

        private int GetTowerPrice(TowerData towerData)
        {
            if (towerData.levels != null && towerData.levels.Length > 0)
            {
                return towerData.levels[0].cost;
            }
            return 0;
        }

        private void SetupButtonManually(GameObject buttonObj, TowerData towerData)
        {
            Text nameText = buttonObj.GetComponentInChildren<Text>();
            if (nameText != null)
            {
                nameText.text = towerData.towerName;
            }

            Image[] images = buttonObj.GetComponentsInChildren<Image>();
            foreach (var img in images)
            {
                if (img.gameObject != buttonObj && towerData.icon != null && img.sprite == null)
                {
                    img.sprite = towerData.icon;
                    img.preserveAspect = true;
                    break;
                }
            }

            Button button = buttonObj.GetComponent<Button>();
            if (button != null)
            {
                button.onClick.AddListener(() => OnTowerSelected(towerData));

                bool canAfford = GameManager.Instance.HasEnoughGold(towerData.levels[0].cost);
                button.interactable = canAfford;
            }
        }

        public void OnTowerSelected(TowerData towerData)
        {
            Debug.Log($"📞 OnTowerSelected 被调用！塔: {towerData?.towerName}, _currentSlot: {_currentSlot != null}");

            if (_currentSlot == null || towerData == null)
            {
                Debug.LogError("❌ _currentSlot 或 towerData 是 null！");
                return;
            }

            Debug.Log($"📦 准备放置塔: {towerData.towerName}, 消耗金币: {towerData.levels[0].cost}");

            bool success = _currentSlot.PlaceTower(towerData);
            Debug.Log($"📦 PlaceTower 返回: {success}");

            if (success)
            {
                Debug.Log("✅ 塔放置成功！");
                // 面板常驻，不隐藏；刷新按钮状态
                _currentSlot = null;
                UpdateButtonStates();
            }
            else
            {
                Debug.LogWarning("⚠️ 塔放置失败！");
            }
        }

        public void UpdateButtonStates()
        {
            foreach (Transform child in _towerButtonContainer)
            {
                TowerButton button = child.GetComponent<TowerButton>();
                if (button != null)
                {
                    button.UpdateState();
                }
            }
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateButtonStates();
        }
    }

    public class TowerButton : MonoBehaviour
    {
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _costText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Image _icon;

        private TowerData _towerData;
        private TowerSelectPanel _panel;

        public void Initialize(TowerData towerData, TowerSelectPanel panel)
        {
            _towerData = towerData;
            _panel = panel;

            if (_nameText != null)
            {
                _nameText.text = towerData.towerName;
            }

            TowerData.TowerStats stats = towerData.levels[0];
            if (_costText != null)
            {
                _costText.text = $"{stats.cost} G";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"范围: {stats.attackRange}";
            }

            if (towerData.icon != null)
            {
                if (_icon != null)
                {
                    _icon.sprite = towerData.icon;
                    _icon.gameObject.SetActive(true);
                }

                Image[] allImages = GetComponentsInChildren<Image>();
                foreach (var img in allImages)
                {
                    if (img.gameObject != gameObject && img.sprite == null)
                    {
                        img.sprite = towerData.icon;
                        img.preserveAspect = true;
                        break;
                    }
                }
            }
            else
            {
                if (_icon != null)
                {
                    _icon.gameObject.SetActive(false);
                }
            }

            UpdateState();

            Button button = GetComponent<Button>();
            if (button != null)
            {
                Debug.Log($"🔘 找到Button组件，准备添加点击监听器...");
                button.onClick.AddListener(OnClicked);
                Debug.Log($"🔘 点击监听器已添加！当前监听器数量: {button.onClick.GetPersistentEventCount()}");
            }
            else
            {
                Debug.LogError("❌ 找不到Button组件！");
            }
        }

        public void UpdateState()
        {
            Button button = GetComponent<Button>();
            if (button != null)
            {
                bool canAfford = GameManager.Instance.HasEnoughGold(_towerData.levels[0].cost);
                button.interactable = canAfford;

                Image image = GetComponent<Image>();
                if (image != null)
                {
                    image.color = canAfford ? Color.white : Color.grey;
                }
            }
        }

        private void OnClicked()
        {
            Debug.Log($"🖱️ TowerButton.OnClicked 被调用！塔: {_towerData?.towerName}, panel: {_panel != null}");

            if (_panel != null)
            {
                Debug.Log($"📞 调用 _panel.OnTowerSelected...");
                _panel.OnTowerSelected(_towerData);
            }
            else
            {
                Debug.LogError("❌ _panel 是 null！");
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class TowerInfoPanel : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private GameObject _panel;

        [Header("Tower Info")]
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _damageText;
        [SerializeField] private Text _rangeText;
        [SerializeField] private Text _attackSpeedText;

        [Header("Buttons")]
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;
        [SerializeField] private Button _closeButton;

        private TowerDefense.Tower.Tower _currentTower;

        private void Awake()
        {
            if (_panel != null)
            {
                _panel.SetActive(false);
            }

            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }

            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }

            if (_closeButton != null)
            {
                _closeButton.onClick.AddListener(Hide);
            }
        }

        public void Show(TowerDefense.Tower.Tower tower)
        {
            _currentTower = tower;

            UpdateTowerInfo();

            if (_panel != null)
            {
                _panel.SetActive(true);
            }

            tower.OnUpgrade += OnTowerUpgraded;
            tower.OnSell += OnTowerSold;
        }

        public void Hide()
        {
            if (_currentTower != null)
            {
                _currentTower.OnUpgrade -= OnTowerUpgraded;
                _currentTower.OnSell -= OnTowerSold;
            }

            _currentTower = null;

            if (_panel != null)
            {
                _panel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_currentTower == null) return;

            var data = _currentTower.Data;
            var stats = _currentTower.CurrentStats;

            if (_towerNameText != null)
            {
                _towerNameText.text = data.towerName;
            }

            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"等级 {_currentTower.CurrentLevel}/{data.levels.Length}";
            }

            if (_damageText != null)
            {
                _damageText.text = $"伤害: {stats.damage}";
            }

            if (_rangeText != null)
            {
                _rangeText.text = $"攻击范围: {stats.attackRange}";
            }

            if (_attackSpeedText != null)
            {
                _attackSpeedText.text = $"攻击速度: {stats.attackSpeed:0.0}";
            }

            UpdateUpgradeButton();
            UpdateSellButton();
        }

        private void UpdateUpgradeButton()
        {
            if (_upgradeButton == null || _upgradeCostText == null) return;

            if (_currentTower.IsMaxLevel)
            {
                _upgradeButton.interactable = false;
                _upgradeCostText.text = "已满级";
                _upgradeCostText.color = Color.grey;
            }
            else
            {
                int upgradeCost = _currentTower.GetUpgradeCost();
                bool canAfford = GameManager.Instance.HasEnoughGold(upgradeCost);

                _upgradeButton.interactable = canAfford;
                _upgradeCostText.text = $"升级（{upgradeCost}金币）";
                _upgradeCostText.color = canAfford ? Color.yellow : Color.red;
            }
        }

        private void UpdateSellButton()
        {
            if (_sellValueText == null) return;

            int sellValue = _currentTower.GetSellValue();
            _sellValueText.text = $"出售（{sellValue}金币）";
        }

        private void OnUpgradeClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Upgrade();
            }
        }

        private void OnSellClicked()
        {
            if (_currentTower != null)
            {
                _currentTower.Sell();
            }
        }

        private void OnTowerUpgraded(TowerDefense.Tower.Tower tower)
        {
            UpdateTowerInfo();
        }

        private void OnTowerSold(TowerDefense.Tower.Tower tower)
        {
            Hide();
        }

        private void OnEnable()
        {
            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnDisable()
        {
            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            if (_panel != null && _panel.activeSelf && _currentTower != null)
            {
                UpdateUpgradeButton();
            }
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Tower;

namespace TowerDefense.UI
{
    public class ClickOutsideHandler : MonoBehaviour, IPointerClickHandler
    {
        [SerializeField] private TowerSlot[] _towerSlots;

        public void OnPointerClick(PointerEventData eventData)
        {
            HideAllPanels();
            DeselectAllSlots();
        }

        private void HideAllPanels()
        {
            TowerSelectPanel selectPanel = FindObjectOfType<TowerSelectPanel>();
            if (selectPanel != null)
            {
                selectPanel.Hide();
            }

            TowerInfoPanel infoPanel = FindObjectOfType<TowerInfoPanel>();
            if (infoPanel != null)
            {
                infoPanel.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

        private void DeselectAllSlots()
        {
            if (_towerSlots == null || _towerSlots.Length == 0)
            {
                _towerSlots = FindObjectsOfType<TowerSlot>();
            }

            foreach (var slot in _towerSlots)
            {
                slot.DeselectSlot();
            }
        }
    }
}

