using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

// 1. 修改 Main Camera → 正交 + 2.5D 角度
var cam = Camera.main;
if (cam != null)
{
    cam.orthographic = true;
    cam.orthographicSize = 8f;
    cam.transform.position = new Vector3(5f, 10f, -5f);
    cam.transform.rotation = Quaternion.Euler(35f, 45f, 0f);
    cam.backgroundColor = new Color(0.53f, 0.81f, 1f, 1f); // 浅蓝背景
    Debug.Log("[2.5D] 摄像机已设为正交+2.5D角度");
}
else
{
    Debug.LogError("[2.5D] 未找到 Main Camera");
}

// 2. 创建地面 Plane
var existingGround = GameObject.Find("Ground");
if (existingGround == null)
{
    var ground = GameObject.CreatePrimitive(PrimitiveType.Plane);
    ground.name = "Ground";
    ground.transform.position = new Vector3(5f, 0f, 5f);
    ground.transform.localScale = new Vector3(2f, 1f, 2f); // 20x20 units
    ground.layer = LayerMask.NameToLayer("Default");

    // 给地面一个绿色材质
    var renderer = ground.GetComponent<Renderer>();
    var mat = new Material(Shader.Find("Universal Render Pipeline/Lit"));
    mat.color = new Color(0.45f, 0.72f, 0.35f); // 草绿色
    renderer.sharedMaterial = mat;

    Undo.RegisterCreatedObjectUndo(ground, "创建地面");
    Debug.Log("[2.5D] 地面已创建");
}

// 3. 删除旧的 2D Sprite 占位建筑（保留传送门）
string[] toDelete = { "GoldMine", "LumberMill", "Quarry", "Fountain", "GrassBG", "HomeBaseHouse" };
int deleted = 0;
foreach (var name in toDelete)
{
    var go = GameObject.Find(name);
    if (go != null)
    {
        Undo.DestroyObjectImmediate(go);
        deleted++;
    }
}
Debug.Log($"[2.5D] 删除 {deleted} 个旧2D对象");

// 4. 保留传送门但调整到 XZ 平面
foreach (var portal in new[] { "Portal_TD", "Portal_Match3" })
{
    var go = GameObject.Find(portal);
    if (go != null)
    {
        var pos = go.transform.position;
        go.transform.position = new Vector3(pos.x, 0f, pos.y); // Y→Z
        go.transform.localScale = Vector3.one;
        Debug.Log($"[2.5D] {portal} 调整到XZ平面");
    }
}

EditorSceneManager.MarkAllScenesDirty();
Debug.Log("[2.5D] 场景改造完成！");

using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

// 用名称找摄像机
var camObj = GameObject.Find("Main Camera");
if (camObj != null)
{
    var cam = camObj.GetComponent<Camera>();
    if (cam != null)
    {
        cam.orthographic = true;
        cam.orthographicSize = 8f;
        cam.transform.position = new Vector3(5f, 10f, -5f);
        cam.transform.rotation = Quaternion.Euler(35f, 45f, 0f);
        cam.backgroundColor = new Color(0.53f, 0.81f, 1f, 1f);
        camObj.tag = "MainCamera";
        Debug.Log("[2.5D] 摄像机已设为正交+2.5D角度");
    }
    else
    {
        Debug.LogError("[2.5D] Main Camera 没有 Camera 组件");
    }
}
else
{
    Debug.LogError("[2.5D] 未找到 Main Camera 对象");
}

EditorSceneManager.MarkAllScenesDirty();

