using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

// 找到 BuildingManager 所在的 GameObject
var bmObj = GameObject.Find("BuildingManager");
if (bmObj == null)
{
    // 尝试从 MANAGERS 下找
    var managers = GameObject.Find("--- MANAGERS ---");
    if (managers != null)
    {
        var homeManager = managers.transform.Find("HomeManager");
        if (homeManager != null)
            bmObj = homeManager.Find("BuildingManager")?.gameObject;
    }
}

if (bmObj != null)
{
    // 添加 GridManager
    var gridMgr = bmObj.GetComponent<GridManager>();
    if (gridMgr == null)
    {
        gridMgr = bmObj.AddComponent<GridManager>();
        Debug.Log("[Setup] GridManager 已添加到 BuildingManager");
    }

    // 添加 BuildModeController
    var buildMode = bmObj.GetComponent<BuildModeController>();
    if (buildMode == null)
    {
        buildMode = bmObj.AddComponent<BuildModeController>();
        Debug.Log("[Setup] BuildModeController 已添加到 BuildingManager");
    }

    // 设置 BuildingManager 的 GridManager 引用
    var serObj = new SerializedObject(bmObj.GetComponent<BuildingManager>());
    var gridProp = serObj.FindProperty("_gridManager");
    if (gridProp != null)
    {
        gridProp.objectReferenceValue = gridMgr;
        serObj.ApplyModifiedProperties();
        Debug.Log("[Setup] BuildingManager._gridManager 已连接");
    }

    // 设置 BuildModeController 的引用
    var serObj2 = new SerializedObject(buildMode);
    var gridProp2 = serObj2.FindProperty("_gridManager");
    var bmProp = serObj2.FindProperty("_buildingManager");
    if (gridProp2 != null)
    {
        gridProp2.objectReferenceValue = gridMgr;
        serObj2.ApplyModifiedProperties();
        Debug.Log("[Setup] BuildModeController._gridManager 已连接");
    }
    if (bmProp != null)
    {
        bmProp.objectReferenceValue = bmObj.GetComponent<BuildingManager>();
        serObj2.ApplyModifiedProperties();
        Debug.Log("[Setup] BuildModeController._buildingManager 已连接");
    }

    EditorSceneManager.MarkAllScenesDirty();
}
else
{
    Debug.LogError("[Setup] 未找到 BuildingManager 对象");
}

