using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

var camObj = GameObject.Find("Main Camera");
if (camObj != null)
{
    var cam = camObj.GetComponent<Camera>();

    // 2.5D 等距视角：正交 + 30°俯角 + 45°偏转
    cam.orthographic = true;
    cam.orthographicSize = 7f;

    // 先算目标点（地面中心 ≈ 5,0,5）
    Vector3 target = new Vector3(5f, 0f, 5f);

    // 俯角 30°、偏转 45° 时，摄像机在目标点的后方偏上
    float distance = 15f;
    float yaw = 45f * Mathf.Deg2Rad;
    float pitch = 30f * Mathf.Deg2Rad;

    Vector3 offset = new Vector3(
        -Mathf.Sin(yaw) * Mathf.Cos(pitch) * distance,
        Mathf.Sin(pitch) * distance,
        -Mathf.Cos(yaw) * Mathf.Cos(pitch) * distance
    );

    cam.transform.position = target + offset;
    cam.transform.rotation = Quaternion.Euler(30f, 45f, 0f);
    cam.backgroundColor = new Color(0.53f, 0.81f, 1f, 1f);

    Debug.Log($"[Camera] 位置: {cam.transform.position}, 旋转: {cam.transform.rotation.eulerAngles}");

    EditorSceneManager.MarkAllScenesDirty();
}

