using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

var camObj = GameObject.Find("Main Camera");
if (camObj != null)
{
    var cam = camObj.GetComponent<Camera>();

    // 地面中心
    Vector3 target = new Vector3(5f, 0f, 5f);

    // 正等距视角：俯角 35.264° (arctan(1/√2)) + 45° 偏转
    // 这样 X/Y/Z 三个轴向在屏幕上投影完全等长，是经典等距
    float pitch = 35.264f;
    float yaw = 45f;

    // 摄像机看向 target，从 target 的后上方偏移
    float dist = 15f;
    float yawRad = yaw * Mathf.Deg2Rad;
    float pitchRad = pitch * Mathf.Deg2Rad;

    Vector3 offset = new Vector3(
        -Mathf.Sin(yawRad) * Mathf.Cos(pitchRad) * dist,
        Mathf.Sin(pitchRad) * dist,
        -Mathf.Cos(yawRad) * Mathf.Cos(pitchRad) * dist
    );

    cam.transform.position = target + offset;

    // 用 LookAt 确保摄像机正对目标点
    cam.transform.LookAt(target);

    cam.orthographic = true;
    cam.orthographicSize = 7f;
    cam.backgroundColor = new Color(0.53f, 0.81f, 1f, 1f);

    Debug.Log($"[Camera] 位置: {cam.transform.position}");
    Debug.Log($"[Camera] 旋转: {cam.transform.rotation.eulerAngles}");
    Debug.Log($"[Camera] Forward: {cam.transform.forward}");

    EditorSceneManager.MarkAllScenesDirty();
}

