using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

// 1. 删除旧的平面 Ground
var oldGround = GameObject.Find("Ground");
if (oldGround != null)
{
    Undo.DestroyObjectImmediate(oldGround);
    Debug.Log("[Ground] 旧平面已删除");
}

// 2. 用 Terrain 创建波西亚风格的地面
var terrainData = new TerrainData();
terrainData.size = new Vector3(30f, 1f, 30f);
terrainData.heightmapResolution = 65;
terrainData.alphamapResolution = 64;

// 给地形添加草地层
var layers = new TerrainLayer[2];

// 草地层
layers[0] = new TerrainLayer();
layers[0].diffuseTexture = CreateGrassTexture();
layers[0].tileSize = new Vector2(3f, 3f);
layers[0].name = "Grass";

// 泥土层
layers[1] = new TerrainLayer();
layers[1].diffuseTexture = CreateDirtTexture();
layers[1].tileSize = new Vector3(4f, 4f);
layers[1].name = "Dirt";

terrainData.terrainLayers = layers;

// 设置混合贴图（主要草地，边缘少量泥土）
float[,,] alphamaps = new float[terrainData.alphamapWidth, terrainData.alphamapHeight, 2];
for (int y = 0; y < terrainData.alphamapHeight; y++)
{
    for (int x = 0; x < terrainData.alphamapWidth; x++)
    {
        float grassWeight = 0.9f;
        // 边缘加些泥土
        float edgeDist = Mathf.Min(x, y, terrainData.alphamapWidth - 1 - x, terrainData.alphamapHeight - 1 - y);
        if (edgeDist < 5f)
            grassWeight = 0.6f;

        alphamaps[x, y, 0] = grassWeight;
        alphamaps[x, y, 1] = 1f - grassWeight;
    }
}
terrainData.SetAlphamaps(0, 0, alphamaps);

// 微调高度让地面有轻微起伏
float[,] heights = terrainData.GetHeights(0, 0, terrainData.heightmapWidth, terrainData.heightmapHeight);
for (int y = 0; y < terrainData.heightmapHeight; y++)
{
    for (int x = 0; x < terrainData.heightmapWidth; x++)
    {
        // 轻微起伏
        heights[y, x] = Mathf.PerlinNoise(x * 0.1f, y * 0.1f) * 0.02f;
    }
}
terrainData.SetHeights(0, 0, heights);

// 保存 terrainData
if (!AssetDatabase.IsValidFolder("Assets/Terrain"))
    AssetDatabase.CreateFolder("Assets", "Terrain");
AssetDatabase.CreateAsset(terrainData, "Assets/Terrain/HomeTerrain.asset");

var terrainGO = Terrain.CreateTerrainGameObject(terrainData);
terrainGO.name = "Ground";
terrainGO.transform.position = new Vector3(-5f, -0.1f, -5f);

Undo.RegisterCreatedObjectUndo(terrainGO, "创建地形");
Debug.Log("[Ground] 波西亚风格地形已创建");

// 3. 应用天空盒占位
AssetDatabase.Refresh();
var skyboxMat = AssetDatabase.LoadAssetAtPath<Material>("Assets/TJGenerators/History/Skybox_20260608_091151_material.mat");
if (skyboxMat != null)
{
    RenderSettings.skybox = skyboxMat;
    DynamicGI.UpdateEnvironment();
    Debug.Log("[Skybox] 占位天空盒已应用");
}

EditorSceneManager.MarkAllScenesDirty();

// 辅助方法：生成草地纹理
Texture2D CreateGrassTexture()
{
    var tex = new Texture2D(256, 256);
    for (int y = 0; y < 256; y++)
    {
        for (int x = 0; x < 256; x++)
        {
            float n = Mathf.PerlinNoise(x * 0.05f, y * 0.05f);
            float r = 0.35f + n * 0.15f;
            float g = 0.6f + n * 0.15f;
            float b = 0.2f + n * 0.05f;
            tex.SetPixel(x, y, new Color(r, g, b));
        }
    }
    tex.Apply();
    tex.wrapMode = TextureWrapMode.Repeat;
    return tex;
}

// 辅助方法：生成泥土纹理
Texture2D CreateDirtTexture()
{
    var tex = new Texture2D(256, 256);
    for (int y = 0; y < 256; y++)
    {
        for (int x = 0; x < 256; x++)
        {
            float n = Mathf.PerlinNoise(x * 0.08f + 100f, y * 0.08f + 100f);
            float r = 0.55f + n * 0.1f;
            float g = 0.4f + n * 0.08f;
            float b = 0.25f + n * 0.05f;
            tex.SetPixel(x, y, new Color(r, g, b));
        }
    }
    tex.Apply();
    tex.wrapMode = TextureWrapMode.Repeat;
    return tex;
}

